const QUESTIONS_CHFI_C5 = [
  { id:70901, domain:6, level:1, question:"Which type of malware replicates itself and spreads across networks without requiring a host file or user action?", options:["A worm self-propagates across networks automatically without needing to attach to a host file or await user execution","A virus that must attach to a host file and run when the user executes that infected file to spread","A trojan that disguises itself as legitimate software and relies on the user choosing to run it in this scenario as well.","A logic bomb that stays dormant until a specific date or condition triggers its malicious payload"], correct:0, explanation:"A virus requires a host file and user execution, and a trojan relies on user deception, so neither self-propagates like a worm." },
  { id:70902, domain:6, level:1, question:"What best describes a trojan horse in malware forensics?", options:["Self-replicating code that spreads automatically across networked hosts without any user interaction at all","Malware disguised as legitimate or desirable software that tricks the user into executing the hidden payload","Code that encrypts victim files and then demands a ransom payment for the decryption key to be released","A hidden toolkit that subverts the operating system kernel to conceal processes, files, and network activity"], correct:1, explanation:"Self-replication describes a worm, encryption-for-ransom describes ransomware, and kernel concealment describes a rootkit, not a trojan." },
  { id:70903, domain:6, level:1, question:"Which malware type is specifically designed to encrypt a victim's files and demand payment for decryption?", options:["A rootkit that hides its presence deep in the operating system while giving an attacker persistent access","A keylogger that silently records keystrokes to steal passwords and other sensitive typed information","Ransomware encrypts the victim's data and demands a payment, typically in cryptocurrency, for the decryption key","A backdoor that quietly opens an alternate access channel bypassing normal authentication mechanisms in this scenario as well."], correct:2, explanation:"A rootkit hides presence, a keylogger records keystrokes, and a backdoor opens covert access, but none encrypt files for ransom." },
  { id:70904, domain:6, level:2, question:"A Remote Access Trojan (RAT) primarily provides an attacker with which capability?", options:["Automatic self-replication that floods a network segment with copies to consume all available bandwidth","Encryption of every document on the disk followed by an on-screen ransom note demanding Bitcoin","Firmware-level persistence that survives a full disk wipe and reinstallation of the operating system","Covert remote control of the infected system, letting the attacker execute commands and exfiltrate data"], correct:3, explanation:"Self-replication is a worm behavior, disk encryption is ransomware, and firmware persistence is a bootkit trait, not the RAT's remote-control function." },
  { id:70905, domain:6, level:2, question:"Which characteristic distinguishes fileless malware from traditional malware?", options:["Fileless malware operates primarily in memory using legitimate system tools, leaving little on-disk footprint","Fileless malware always writes a large encrypted executable to disk that antivirus can trivially detect","Fileless malware requires a signed kernel driver to be installed before any of its code can run at all in this scenario as well.","Fileless malware can only infect systems that have no endpoint protection or antivirus software installed"], correct:0, explanation:"Fileless malware avoids writing files rather than dropping large executables, needs no kernel driver, and can affect protected systems by abusing living-off-the-land tools." },
  { id:70906, domain:6, level:2, question:"A rootkit that operates at Ring 0 of the processor is best classified as which type?", options:["A user-mode rootkit that only hooks application-level APIs and runs with limited standard user permissions","A kernel-mode rootkit runs at Ring 0 with full privileges, making it powerful and difficult to detect or remove","A hardware rootkit embedded in the network interface card firmware separate from the operating system entirely","A hypervisor rootkit that installs beneath the operating system by virtualizing the running host machine in this scenario as well."], correct:1, explanation:"User-mode rootkits run at Ring 3, hardware rootkits live in device firmware, and hypervisor rootkits sit below the OS, so none match Ring 0 kernel mode." },
  { id:70907, domain:6, level:1, question:"What is a botnet in the context of malware?", options:["A single isolated infected host that has no ability to communicate with any external control server at all","A legitimate distributed computing grid used by academic researchers to share processing power for science","A network of compromised machines controlled by an attacker through a command-and-control infrastructure","A hardware appliance that filters malicious traffic at the network perimeter before it reaches any hosts"], correct:2, explanation:"A botnet is many controlled hosts, not one isolated machine, not a legitimate research grid, and not a defensive filtering appliance." },
  { id:70908, domain:6, level:2, question:"During static malware analysis, why is calculating a file's cryptographic hash an early step?", options:["The hash decrypts any packed sections of the binary so the underlying original code becomes readable at once","The hash reveals the exact command-and-control IP addresses the malware will contact when it is executed","The hash automatically unpacks UPX compression and rebuilds the import table for the analyst to review in this scenario as well.","The hash uniquely identifies the sample so it can be checked against threat intelligence and reference databases"], correct:3, explanation:"A hash only fingerprints the file; it does not decrypt, reveal C2 addresses, or unpack the binary." },
  { id:70909, domain:6, level:1, question:"Which tool would an analyst use to extract human-readable ASCII and Unicode text from a suspicious binary?", options:["The strings utility scans a binary and outputs sequences of printable characters that may reveal useful clues","A network sniffer that captures packets on the wire while the malware is actively communicating outward","A disk imaging tool that produces a bit-for-bit forensic copy of the entire storage device for analysis","A registry editor used to browse and modify Windows configuration hive keys and their stored values in this scenario as well."], correct:0, explanation:"A sniffer captures traffic, an imaging tool copies disks, and a registry editor edits config keys; only strings extracts embedded text." },
  { id:70910, domain:6, level:2, question:"What does the presence of a UPX signature in a PE file typically indicate to an analyst?", options:["The executable is digitally signed by a trusted vendor and can therefore be considered clean and benign","The executable has been packed with UPX compression and likely needs unpacking before meaningful analysis","The executable is a benign UPS shipping tracker application with no relationship to malware whatsoever","The executable has already been fully analyzed and its complete behavior report is embedded inside it in this scenario as well."], correct:1, explanation:"UPX is a packer, not a trust signal, not shipping software, and not an embedded report, so unpacking is required." },
  { id:70911, domain:6, level:2, question:"In PE header analysis, an unusually small number of imported functions combined with high entropy suggests what?", options:["The binary is a normal, clean, statically linked program with no obfuscation or compression whatsoever in this scenario as well.","The binary is a plain text configuration file that was accidentally given an executable file extension","The binary is likely packed or obfuscated, hiding its true imports until it is unpacked in memory at runtime","The binary has been fully decompiled to readable source code and no further analysis is possible on it"], correct:2, explanation:"Few imports plus high entropy point to packing; a clean program shows normal imports, and it is not text or decompiled source." },
  { id:70912, domain:6, level:2, question:"What is the primary purpose of a YARA rule in malware analysis?", options:["To automatically remove any detected malware from an infected endpoint and repair the damaged files","To encrypt an analyst's own toolset so that malware cannot tamper with the investigation utilities","To generate a forensic disk image of the compromised host for later chain-of-custody preservation in this scenario as well.","To define string and byte patterns that identify and classify malware samples across files and memory"], correct:3, explanation:"YARA matches patterns to classify samples; it does not remediate, encrypt tools, or image disks." },
  { id:70913, domain:6, level:3, question:"An analyst writes a YARA rule with a condition of '2 of ($s*)'. What does this condition require?", options:["At least two of the string identifiers beginning with s must match for the rule to trigger on a file","Exactly two bytes at the very start of the file must equal the ASCII characters s and asterisk in order","The file must be precisely two megabytes in size before any of the string patterns are even evaluated","Every string in the rule must match twice each before the rule is permitted to report a positive result"], correct:0, explanation:"The condition means two of the s-prefixed strings must match, not a byte check, size check, or an all-match-twice rule." },
  { id:70914, domain:6, level:2, question:"What information does VirusTotal aggregate when a sample hash is submitted?", options:["A single authoritative verdict from one government agency that legally determines if the file is malware","Detection results from many antivirus engines plus community and behavioral metadata about the sample","The full decrypted source code of the malware reconstructed automatically from the uploaded binary","A guaranteed clean bill of health for any file that no engine currently flags as malicious right now"], correct:1, explanation:"VirusTotal aggregates many engines and metadata, not one agency verdict, not source code, and a no-detection result is not a guarantee of safety." },
  { id:70915, domain:6, level:1, question:"Which of the following is an example of a static analysis technique?", options:["Running the malware inside a sandbox and observing the registry keys it creates during its execution","Capturing live network packets the sample sends to its command-and-control server while it is running","Examining a binary's PE header and imported functions without ever executing the sample on a system","Monitoring the API calls the malware makes to the operating system as the process actively executes"], correct:2, explanation:"The other three all involve running the sample and observing behavior, which is dynamic analysis, not static." },
  { id:70916, domain:6, level:2, question:"Cuckoo Sandbox is primarily used for which purpose in malware investigations?", options:["Static disassembly of a binary into assembly instructions without ever running the sample at all in this scenario as well.","Cryptographic hashing of every file on a suspect disk to build an inventory for chain of custody","Recovering deleted partitions from a damaged hard drive so their file systems can be reconstructed","Automated dynamic analysis that executes a sample in isolation and reports its behavior and artifacts"], correct:3, explanation:"Cuckoo runs samples for behavioral analysis; it is not a disassembler, hashing inventory tool, or partition recovery utility." },
  { id:70917, domain:6, level:2, question:"During dynamic analysis, monitoring which of the following best reveals a sample's persistence attempts?", options:["Watching for new autorun registry keys, scheduled tasks, and services created by the running sample","Counting the total number of assembly instructions present in the disassembled listing of the binary","Measuring the file's Shannon entropy to determine whether its code sections appear compressed or packed","Reading the compile timestamp stored in the PE header to estimate when the malware was first built"], correct:0, explanation:"Persistence appears as autorun keys, tasks, and services at runtime; instruction counts, entropy, and timestamps are static traits." },
  { id:70918, domain:6, level:3, question:"Why do many malware analysts run samples inside virtual machines with snapshots?", options:["Virtual machines make the malware run faster so its full payload executes before the analyst can react","Snapshots let the analyst instantly revert the infected VM to a clean state after observing the behavior","Snapshots permanently encrypt the malware so it can never be executed a second time on any host again in this scenario as well.","Virtual machines guarantee the malware can never detect that it is running in an analysis environment"], correct:1, explanation:"Snapshots enable clean reverts; VMs do not speed malware, do not encrypt it, and cannot guarantee undetectability since malware often detects VMs." },
  { id:70919, domain:6, level:2, question:"Which artifact category is most directly observed by using Process Monitor during behavioral analysis?", options:["The precise Bitcoin wallet balance associated with a ransomware operator's cryptocurrency address","The complete assembly-level control flow graph of the binary reconstructed without executing it","Real-time file system, registry, and process activity generated by the sample as it runs on the host","The list of antivirus engines on VirusTotal that currently flag the submitted file hash as malicious"], correct:2, explanation:"Process Monitor captures live file/registry/process events; it does not track wallets, build static CFGs, or query VirusTotal." },
  { id:70920, domain:6, level:2, question:"A sample makes DNS queries to a series of algorithmically generated domain names. This most likely indicates what?", options:["The malware is attempting to legitimately update itself from the software vendor's official update servers","The malware has failed to execute and is only producing meaningless random network noise on the wire","The malware is performing a routine reverse DNS lookup that all clean applications also perform normally","The malware likely uses a Domain Generation Algorithm to locate its command-and-control server resiliently"], correct:3, explanation:"Algorithmically generated domains signal a DGA for resilient C2, not legitimate updates, execution failure, or routine lookups." },
  { id:70921, domain:6, level:1, question:"What is an Indicator of Compromise (IOC)?", options:["A forensic artifact such as a hash, IP, or registry key that suggests a system may have been breached","A legal document that formally authorizes investigators to seize a suspect's computer equipment now","A hardware token that employees use to authenticate securely to the corporate virtual private network","A scheduled maintenance window during which security patches are applied to production systems safely"], correct:0, explanation:"An IOC is forensic evidence of compromise, not a legal seizure authorization, an auth token, or a maintenance window." },
  { id:70922, domain:6, level:3, question:"A sample checks the number of CPU cores and the amount of RAM before executing its payload. This is most likely an example of what?", options:["A legitimate licensing check that verifies the host meets the vendor's minimum hardware requirements first","Anti-analysis sandbox evasion, since analysis VMs often have few cores and little memory compared to real hosts","A performance optimization that tunes the program to use available resources more efficiently at runtime in this scenario as well.","A benign hardware inventory routine used by help-desk staff to catalog corporate endpoint specifications"], correct:1, explanation:"Checking for low-resource environments is classic sandbox evasion, not licensing, optimization, or inventory." },
  { id:70923, domain:6, level:2, question:"Why is memory forensics especially important when investigating fileless malware?", options:["Fileless malware writes a large plaintext log to disk, making memory analysis entirely unnecessary here","Memory forensics is only useful for recovering deleted files from unallocated clusters on the hard disk","Fileless malware resides mainly in RAM, so a memory capture often holds the only recoverable evidence of it","Fileless malware can always be found simply by scanning the file system with a signature-based scanner in this scenario as well."], correct:2, explanation:"Because it lives in RAM and leaves little on disk, memory capture is key; it does not log to disk plainly or appear in file scans." },
  { id:70924, domain:6, level:3, question:"Which Volatility plugin approach would help identify processes hidden by a rootkit through DKOM?", options:["Parsing only the master boot record to recover a deleted partition table from a raw disk image file","Calculating file entropy on disk to determine whether a stored executable has been packed or not","Submitting the memory image to VirusTotal for a multi-engine antivirus scan of its full contents","Cross-referencing process lists such as psscan against pslist to reveal unlinked hidden processes"], correct:3, explanation:"Comparing psscan to pslist exposes DKOM-hidden processes; MBR parsing, entropy calc, and VirusTotal scanning do not address this." },
  { id:70925, domain:6, level:2, question:"What does 'living off the land' mean in the context of fileless malware?", options:["Abusing legitimate built-in system tools like PowerShell and WMI to carry out malicious actions covertly","Dropping a custom compiled executable to disk and registering it as a Windows service for persistence","Physically relocating a compromised server to an off-site data center to evade network investigators in this scenario as well.","Encrypting all victim files and demanding a ransom before the decryption key will be provided to them"], correct:0, explanation:"LOLbins abuse trusted native tools; it does not mean dropping custom binaries, moving hardware, or ransoming files." },
  { id:70926, domain:6, level:2, question:"A memory-resident malware injects code into a legitimate process. Which technique describes this?", options:["Disk defragmentation, which reorganizes file fragments on a storage volume to improve read performance in this scenario as well.","Process injection, where malicious code is written into and executed within the address space of another process","Partition alignment, which adjusts where partitions begin so they map cleanly onto the storage sectors","Certificate pinning, which ties an application to a specific expected TLS certificate for its own server"], correct:1, explanation:"Injecting code into another process is process injection; defragmentation, alignment, and pinning are unrelated concepts." },
  { id:70927, domain:6, level:2, question:"Which Windows registry location is a classic persistence mechanism for malware?", options:["The Recycle Bin metadata store, which merely tracks the original paths of files that the user deleted","The prefetch directory, which only caches application launch data to speed up future program startups","The Run and RunOnce keys under HKCU or HKLM, which launch listed programs automatically at user logon","The thumbnail cache database, which stores small preview images of pictures viewed in File Explorer"], correct:2, explanation:"Run/RunOnce keys auto-launch programs for persistence; Recycle Bin, prefetch, and thumbnail cache are forensic artifacts, not autostart locations." },
  { id:70928, domain:6, level:3, question:"Malware creates a scheduled task that runs a script at every boot. Where would an investigator find evidence of this on Windows?", options:["Only within the volatile clipboard buffer, which is cleared the moment the system is powered off","Exclusively inside the BIOS setup screen, which cannot be examined from the running operating system","Solely in the printer spooler queue, which holds documents awaiting output to an attached printer","In the Task Scheduler library and the System32 Tasks folder along with related event log entries"], correct:3, explanation:"Scheduled tasks appear in the Task Scheduler and Tasks folder with logs; the clipboard, BIOS screen, and print spooler are not where tasks live." },
  { id:70929, domain:6, level:2, question:"A malicious DLL is placed so a legitimate program loads it instead of the intended library. This technique is called what?", options:["DLL search order hijacking, where a rogue DLL is loaded because of how Windows resolves library paths","ARP cache poisoning, which associates an attacker MAC address with a victim IP on the local network","SQL injection, which inserts crafted database queries through unsanitized application input fields in this scenario as well.","Cross-site scripting, which injects client-side scripts into web pages later viewed by other users"], correct:0, explanation:"Loading a rogue DLL via path resolution is search order hijacking; ARP poisoning, SQL injection, and XSS are unrelated attack classes." },
  { id:70930, domain:6, level:2, question:"What is the main goal of code obfuscation in malware?", options:["To increase the raw execution speed of the malware so it completes its payload before detection occurs","To make the malware's logic difficult for analysts and tools to understand, slowing reverse engineering","To reduce the file size of the malware so that it downloads more quickly across slow connections in this scenario as well.","To guarantee the malware is fully compatible with every version of every operating system in use"], correct:1, explanation:"Obfuscation hinders comprehension; it is not primarily about speed, size, or cross-platform compatibility." },
  { id:70931, domain:6, level:3, question:"A malware sample checks whether a debugger is attached by calling IsDebuggerPresent. This is an example of what?", options:["A benign accessibility feature that helps visually impaired users interact with the application interface","A standard exception handler that gracefully recovers the program from an unexpected runtime crash","An anti-debugging technique used to detect and evade dynamic analysis performed with a debugger attached","A memory allocation routine that reserves heap space before the program begins processing input data"], correct:2, explanation:"IsDebuggerPresent is a classic anti-debugging check, not an accessibility feature, exception handler, or allocator." },
  { id:70932, domain:6, level:2, question:"Which technique changes malware code on each infection while keeping behavior identical, defeating simple signatures?", options:["Steganography, which conceals a secret message inside an image without altering the program code at all","Tunneling, which encapsulates one network protocol inside another to bypass firewall filtering rules","Sandboxing, which isolates a running program from the host so its actions cannot affect the system in this scenario as well.","Polymorphism, which mutates the malware's code or encryption on each instance to evade static signatures"], correct:3, explanation:"Polymorphism mutates code to dodge signatures; steganography hides data, tunneling wraps protocols, and sandboxing isolates execution." },
  { id:70933, domain:6, level:2, question:"Malware that decrypts its own payload in memory only at runtime is using which anti-analysis approach?", options:["Runtime unpacking or self-decryption, keeping the payload encrypted on disk to defeat static inspection","A digital code-signing certificate that proves the vendor's identity to the operating system loader","A checksum routine that verifies file integrity so the user knows the download was not corrupted","A compiler optimization flag that strips debug symbols to shrink the final compiled binary size in this scenario as well."], correct:0, explanation:"Self-decrypting at runtime hides the payload from static tools; signing, checksums, and optimization flags do not conceal a payload." },
  { id:70934, domain:6, level:1, question:"What does the Tor network primarily provide to its users?", options:["A guaranteed increase in raw internet bandwidth for streaming high-definition video without buffering","Anonymized communication by routing traffic through multiple relays so the origin is difficult to trace","A centralized directory that publicly lists the real IP address of every person using the network in this scenario as well.","A legally binding certification that all sites accessed through it are safe and government approved"], correct:1, explanation:"Tor anonymizes via layered relays; it does not boost bandwidth, publish user IPs, or certify site safety." },
  { id:70935, domain:6, level:2, question:"A '.onion' address is associated with which of the following?", options:["A top-level domain sold by ordinary registrars and resolvable by any conventional public DNS server","An email attachment format used to compress multiple documents into a single downloadable archive","A Tor hidden service reachable only through the Tor network rather than the standard public internet","A hardware encryption chip built into modern motherboards to store cryptographic keys securely in this scenario as well."], correct:2, explanation:"A .onion address is a Tor hidden service, not a registrar-sold TLD, an archive format, or a hardware chip." },
  { id:70936, domain:6, level:3, question:"Why is deanonymizing Tor hidden service operators particularly challenging for investigators?", options:["Tor stores every user's real name and address in a public ledger that investigators cannot legally read","Hidden services broadcast their physical GPS coordinates, which are encrypted with an unbreakable cipher","All Tor traffic is sent completely unencrypted, but it moves too fast for any tool to capture in time","Layered encryption and multi-relay routing hide the server's true IP, so no single relay knows both ends"], correct:3, explanation:"The design ensures no relay sees both endpoints; Tor keeps no public name ledger, broadcasts no GPS, and does encrypt traffic." },
  { id:70937, domain:6, level:2, question:"In cryptocurrency forensics, what does blockchain 'chain analysis' or tracing attempt to do?", options:["Follow the flow of funds between wallet addresses across the public ledger to link transactions to entities","Decrypt the private keys of every wallet on the network to seize the funds they currently hold in this scenario as well.","Permanently erase suspicious transactions from the blockchain so criminals cannot reuse those coins","Convert all Bitcoin on the network into a government-issued currency at a fixed official exchange rate"], correct:0, explanation:"Chain analysis traces fund flows on the public ledger; it cannot decrypt private keys, erase transactions, or force conversions." },
  { id:70938, domain:6, level:2, question:"Which property of the Bitcoin blockchain actually aids forensic investigators despite pseudonymity?", options:["Each transaction automatically embeds the sender's full legal name and residential address in the ledger","Every transaction is permanently recorded on a public ledger, allowing analysts to trace the movement of funds","The ledger is private and only viewable by the two specific parties involved in each individual transaction","Transactions are automatically deleted after ninety days, giving investigators a fixed evidence window in this scenario as well."], correct:1, explanation:"The public, permanent ledger aids tracing; it does not embed legal identities, stay private, or auto-delete entries." },
  { id:70939, domain:6, level:3, question:"A ransomware operator moves stolen Bitcoin through a 'mixing' or 'tumbling' service. What is the investigative impact?", options:["Mixers publicly announce the operator's identity to the blockchain, making attribution immediately trivial","Mixers convert the Bitcoin into a fully traceable format that removes all pseudonymity from the coins","Mixers blend many users' coins to obscure the transaction trail, complicating attribution of the funds","Mixers freeze the funds so that they can never be spent, effectively ending the investigation on the spot"], correct:2, explanation:"Mixers obscure the trail to hinder attribution; they do not reveal identities, remove pseudonymity, or freeze funds." },
  { id:70940, domain:6, level:1, question:"Which browser is most commonly used to access dark web sites?", options:["A standard Chrome installation with no extensions, connecting directly over the ordinary public internet","A basic FTP client designed only for transferring files between servers over the file transfer protocol","A command-line email client that retrieves messages from a mailbox using the POP3 or IMAP protocols","The Tor Browser, which is configured to route connections through the Tor anonymity network by default"], correct:3, explanation:"The Tor Browser accesses .onion sites; plain Chrome, an FTP client, and an email client cannot reach hidden services by design." },
  { id:70941, domain:6, level:2, question:"Which operational security mistake has commonly led to dark web marketplace operators being deanonymized?", options:["Reusing an identifiable username, email, or Bitcoin address that links their clearnet identity to the market","Encrypting all of their communications with strong, up-to-date, and correctly configured modern cryptography","Hosting the marketplace exclusively as a Tor hidden service with no clearnet exposure of any kind at all","Paying for hosting anonymously using freshly generated cryptocurrency that was never reused anywhere else"], correct:0, explanation:"Identity reuse leaks attribution; strong crypto, hidden-service-only hosting, and fresh anonymous payments are good OPSEC, not mistakes." },
  { id:70942, domain:6, level:2, question:"Which is a common indicator of mobile malware on an Android device?", options:["A slightly slower boot time caused entirely by a routine operating system security update installing itself","Unexplained data usage, battery drain, and apps requesting permissions unrelated to their stated function","The device correctly displaying the current time and date after a scheduled network time synchronization","The presence of a manufacturer-signed system application that ships preinstalled on every such device"], correct:1, explanation:"Excess data, battery drain, and odd permissions signal malware; a normal update, correct clock, and signed system app are benign." },
  { id:70943, domain:6, level:3, question:"During mobile malware analysis, why would an investigator decompile an APK's DEX bytecode?", options:["To physically replace the phone's battery so the device can stay powered during the entire analysis session","To increase the phone's cellular signal strength so that downloads complete faster during the investigation","To recover a readable representation of the app's logic and reveal hidden malicious functionality inside it","To reformat the SD card so that any deleted photos are permanently and irrecoverably overwritten on it"], correct:2, explanation:"Decompiling DEX exposes app logic for analysis; it has nothing to do with batteries, signal strength, or wiping storage." },
  { id:70944, domain:6, level:2, question:"What does the MITRE ATT&CK framework primarily catalog?", options:["A list of approved antivirus vendors that a company is legally required to purchase its software from in this scenario as well.","The retail prices of exploit kits currently for sale on various underground criminal marketplaces online","A ranked leaderboard of the fastest supercomputers used for cracking password hashes across the world","Adversary tactics, techniques, and procedures observed in real-world intrusions across the attack lifecycle"], correct:3, explanation:"ATT&CK catalogs adversary TTPs; it is not a vendor list, a price catalog, or a supercomputer ranking." },
  { id:70945, domain:6, level:2, question:"STIX and TAXII are standards associated with which activity?", options:["Structuring and exchanging cyber threat intelligence in a machine-readable format between organizations","Physically imaging a hard drive so that a bit-for-bit forensic copy is preserved for court evidence in this scenario as well.","Compressing large log files on disk to save storage space in a security information and event system","Encrypting emails end-to-end so that only the intended recipient can read the message contents fully"], correct:0, explanation:"STIX structures threat intel and TAXII transports it; they are not about disk imaging, log compression, or email encryption." },
  { id:70946, domain:6, level:3, question:"An analyst extracts a hardcoded IP, a mutex name, and a file hash from a sample to share with peers. These are best described as what?", options:["Digital forensic search warrants that legally authorize the seizure of the attacker's remote servers","Indicators of compromise that other defenders can use to detect the same threat in their environments","Encryption keys that will decrypt any files the ransomware has locked on the victim's hard drive","Software license activation codes that unlock premium features of a commercial analysis toolkit in this scenario as well."], correct:1, explanation:"Hashes, IPs, and mutexes are IOCs for detection; they are not warrants, decryption keys, or license codes." },
  { id:70947, domain:6, level:1, question:"What is a file hash's role as an Indicator of Compromise?", options:["It reveals the plaintext password the malware used to authenticate to its command server remotely","It automatically quarantines and deletes any matching file the moment it appears on any endpoint","It provides a unique fingerprint that lets defenders detect the exact same malicious file elsewhere","It rewrites the malware's code so that future variants can no longer evade signature detection in this scenario as well."], correct:2, explanation:"A hash is a detection fingerprint; it does not reveal passwords, auto-quarantine files, or rewrite malware." },
  { id:70948, domain:6, level:2, question:"A worm exploits a network service vulnerability to spread. Which log source would best show its lateral movement?", options:["The desktop wallpaper history, which records only the images a user has set as their background over time","The printer toner level logs, which merely track when consumables need to be replaced on office printers in this scenario as well.","The screensaver activation records, which note when the display idle timeout engaged on each workstation","Network flow and firewall logs showing unexpected connections between internal hosts on the exploited port"], correct:3, explanation:"Flow and firewall logs reveal lateral spread; wallpaper, toner, and screensaver records are irrelevant to worm propagation." },
  { id:70949, domain:6, level:1, question:"What is a dropper in malware terminology?", options:["A small program whose job is to install or download the main malicious payload onto the target system","A defensive firewall rule that drops malicious packets before they can reach an internal host at all","A hardware device that physically disconnects a drive to prevent any writes during forensic imaging in this scenario as well.","A backup routine that copies user files to cloud storage on a nightly automated maintenance schedule"], correct:0, explanation:"A dropper installs the payload; it is not a firewall rule, a write blocker, or a backup routine." },
  { id:70950, domain:6, level:2, question:"Which of the following would be considered a host-based IOC rather than a network-based IOC?", options:["A command-and-control domain name that the malware resolves and connects to over the internet regularly","A specific malicious mutex object created in memory by the sample when it runs on an infected machine","A destination IP address that the malware repeatedly beacons to across the corporate network perimeter","A distinctive user-agent string the malware sends inside its outbound HTTP requests to remote servers"], correct:1, explanation:"A mutex is host-based; the domain, IP, and user-agent are all observed on the network, making them network-based IOCs." },
  { id:70951, domain:6, level:3, question:"A ransomware note demands payment to a Bitcoin address. What is the most valuable next investigative step with that address?", options:["Immediately pay the ransom from a corporate wallet so the encrypted files can be recovered right away","Delete the ransom note from the desktop so that other employees are not alarmed by seeing the message","Trace the address on the blockchain to identify where funds flow and whether they reach known exchanges","Reboot every affected server repeatedly in the hope that the encryption process reverses itself on its own"], correct:2, explanation:"Tracing the address can lead to exchanges and attribution; paying, deleting evidence, or rebooting are not sound investigative steps." },
  { id:70952, domain:6, level:2, question:"What does high Shannon entropy in a section of a PE file most strongly suggest?", options:["The section contains ordinary readable English text such as help documentation or license agreements in this scenario as well.","The section is empty padding filled entirely with repeating zero bytes to align the file on the disk","The section is a standard resource table listing icons and version strings for the application shell","The section is likely compressed or encrypted, which is common in packed or obfuscated malware samples"], correct:3, explanation:"High entropy indicates compression or encryption; plain text, zero padding, and resource tables all have low entropy." },
  { id:70953, domain:6, level:2, question:"An analyst uses a disassembler such as IDA or Ghidra to do what during malware analysis?", options:["Translate the binary's machine code into assembly and reconstruct control flow for reverse engineering","Automatically pay any ransom demand embedded in the sample using a preconfigured cryptocurrency wallet","Capture and decrypt all TLS-encrypted network sessions the malware establishes with remote endpoints","Physically clone the suspect's hard drive to a sterile target disk for chain-of-custody preservation"], correct:0, explanation:"Disassemblers turn code into assembly for analysis; they do not pay ransoms, decrypt TLS, or clone disks." },
  { id:70954, domain:6, level:1, question:"Which term describes malware that appears dormant until a specific trigger condition, such as a date, is met?", options:["A worm, which begins spreading immediately across the network the instant it first infects any host in this scenario as well.","A logic bomb, which stays inactive until predefined conditions cause it to detonate its malicious payload","A keylogger, which starts recording keystrokes continuously as soon as it is installed on the system","A scareware pop-up, which appears on screen right away to frighten the user into buying fake software"], correct:1, explanation:"A logic bomb waits for a trigger; a worm spreads at once, a keylogger records immediately, and scareware displays instantly." },
  { id:70955, domain:6, level:3, question:"During memory analysis you find a process with a legitimate name but running from an unusual temp path. What does this most likely indicate?", options:["A completely normal Windows behavior in which all system processes routinely run from temporary folders","A hardware fault in the RAM modules that has randomly corrupted the stored process path string in memory","Masquerading, where malware mimics a trusted process name while executing from a suspicious location","A licensing feature that intentionally relocates trusted processes to temp folders to verify activation"], correct:2, explanation:"A trusted name from an odd path signals masquerading; system processes do not normally run from temp, and it is not RAM fault or licensing." },
  { id:70956, domain:6, level:2, question:"Why might malware use HTTPS for its command-and-control communication?", options:["HTTPS forces the malware to reveal its full source code to any network monitoring device on the path","HTTPS is the only protocol capable of transferring executable files, which malware always requires in this scenario as well.","HTTPS automatically reports the malware's activity to the antivirus vendor for immediate blacklisting","Encryption hides the content of the C2 traffic from inspection, helping the malware blend with normal web usage"], correct:3, explanation:"HTTPS conceals C2 content and mimics legitimate traffic; it does not reveal source, is not the only file transport, and does not report to vendors." },
  { id:70957, domain:6, level:2, question:"What is the purpose of a mutex object that many malware families create on infection?", options:["It ensures only one instance of the malware runs on a host, and its unique name can serve as an IOC","It encrypts the entire hard drive of the victim so that a ransom can be demanded for the key later","It grants the malware administrative privileges automatically without exploiting any vulnerability at all","It physically disables the network card so the infected machine cannot be reached by any investigator"], correct:0, explanation:"A mutex prevents duplicate instances and can be an IOC; it does not encrypt disks, grant admin rights, or disable hardware." },
  { id:70958, domain:6, level:1, question:"What does the term 'payload' refer to in malware?", options:["The legitimate installer wrapper that a security vendor uses to distribute antivirus definition updates","The component of the malware that carries out its intended malicious action once execution succeeds","The physical shipping container in which infected hardware is transported between two data centers","The harmless splash screen that a program shows during startup before its main window appears"], correct:1, explanation:"The payload performs the malicious action; it is not a vendor installer, a shipping container, or a splash screen." },
  { id:70959, domain:6, level:3, question:"An investigator wants to know which files a ransomware encrypted first to understand its behavior. Which artifact is most useful?", options:["The monitor's brightness setting history, which logs only how the display luminance changed over time","The keyboard backlight timer, which records when the illumination behind the keys turned on and off in this scenario as well.","USN journal and MFT records on NTFS, which show the timeline of file modifications during the encryption run","The audio mixer volume levels, which track how loud each application's sound output was set at runtime"], correct:2, explanation:"NTFS USN journal and MFT reveal the encryption timeline; brightness, keyboard backlight, and audio levels carry no such evidence." },
  { id:70960, domain:6, level:2, question:"Which statement about sandbox evasion is accurate?", options:["Sandboxes are undetectable, so no malware has ever been able to alter its behavior when analyzed in one","Evasion means the malware runs faster in a sandbox to complete its payload before the timer expires in this scenario as well.","Evasion requires the analyst's explicit permission, which the malware must request before hiding itself","Malware may delay execution or check for analysis artifacts to avoid revealing behavior inside a sandbox"], correct:3, explanation:"Malware evades by stalling or checking artifacts; sandboxes are detectable, evasion is not about speed, and it needs no permission." },
  { id:70961, domain:6, level:2, question:"A YARA rule includes a 'condition' section. What is its role?", options:["It defines the logical criteria, combining strings and other tests, that must be true for the rule to match","It stores the antivirus vendor's contact email so users know who to notify about false positive matches","It lists the exact ransom amount in Bitcoin that the associated malware family typically demands of victims","It contains the decryption key needed to recover files that the matched malware previously encrypted"], correct:0, explanation:"The condition sets match logic; it is not a contact field, a ransom figure, or a decryption key." },
  { id:70962, domain:6, level:1, question:"What is scareware?", options:["A rootkit that operates silently at the kernel level and never displays anything at all to the user in this scenario as well.","Malware or deceptive software that frightens users with fake alerts to trick them into paying or installing","A worm that spreads across the network without any visible interaction or notification to the victim","A legitimate antivirus product certified by an independent testing laboratory as being fully effective"], correct:1, explanation:"Scareware uses fake alarms to manipulate users; it is not a silent rootkit, a stealthy worm, or a certified antivirus." },
  { id:70963, domain:6, level:3, question:"You suspect a hidden service is hosted within a particular jurisdiction. Which non-Tor technique might help correlate it?", options:["Reading the operator's real IP directly from the .onion address, which openly encodes their location","Querying public DNS for the .onion domain, which resolves to the server's true public IP address in this scenario as well.","Analyzing operational leaks such as server misconfigurations, response timing, or reused infrastructure clues","Sending a legal subpoena to the Tor network's central owner, who keeps records of every hidden service"], correct:2, explanation:"Attribution relies on OPSEC leaks and misconfigurations; .onion addresses do not encode IPs, do not resolve via DNS, and Tor has no central record-keeping owner." },
  { id:70964, domain:6, level:2, question:"What distinguishes a bootkit from a typical rootkit?", options:["A bootkit only runs inside a web browser tab and disappears entirely when that browser is closed down in this scenario as well.","A bootkit is a harmless boot animation that customizes the logo shown while the computer is starting up","A bootkit can only affect printers and other peripherals but never the main computer's operating system","A bootkit infects the boot process, such as the MBR or bootloader, to load before the operating system does"], correct:3, explanation:"A bootkit compromises the boot chain to load early; it is not a browser artifact, a boot animation, or a peripheral-only threat." },
  { id:70965, domain:6, level:2, question:"What is the benefit of comparing a sample's effects to a known-good baseline of a system?", options:["Differences from the baseline highlight files, registry keys, and processes the malware added or changed","The baseline automatically removes the malware and restores the system without any analyst intervention in this scenario as well.","The baseline encrypts the malware sample so it can be safely emailed to colleagues for a second opinion","The baseline guarantees that the malware will never be able to execute on that particular machine again"], correct:0, explanation:"Baseline comparison surfaces changes the malware made; it does not remediate, encrypt samples, or immunize the host." },
  { id:70966, domain:6, level:1, question:"Which is a legitimate reason to use a hash set like the NIST NSRL during analysis?", options:["To decrypt any encrypted malware payload instantly by looking the ciphertext up in the hash database in this scenario as well.","To quickly filter out known-good system files so investigators focus only on unknown or suspicious files","To generate new malware variants for offensive testing against the organization's own defenses safely","To permanently delete every file on the suspect drive that does not appear in the reference set at all"], correct:1, explanation:"Known-good hash sets reduce noise by excluding trusted files; they do not decrypt payloads, generate malware, or delete files." },
  { id:70967, domain:6, level:3, question:"A packed sample must be unpacked before static analysis. What is the safest general approach to obtain the unpacked code?", options:["Simply rename the file extension to txt, which forces Windows to reveal the fully unpacked source code","Upload it to a public forum and wait for a stranger to post the unpacked binary back in the replies","Run it under monitoring in an isolated environment and dump the process memory after it self-unpacks","Open it in a plain text editor and manually retype what appears there to reconstruct the original code"], correct:2, explanation:"Dumping memory after self-unpacking in isolation works; renaming, crowdsourcing, or retyping do not unpack a binary." },
  { id:70968, domain:6, level:2, question:"What is the significance of the compile timestamp in a PE header during analysis?", options:["It is a cryptographically signed value that can never be altered and therefore proves the exact build date","It records the precise moment the victim first executed the malware on their own infected machine host","It contains the attacker's time zone and home address encoded directly into the executable file header","It can suggest when the sample was built, though attackers may forge it, so it is treated as a soft clue"], correct:3, explanation:"The timestamp is a soft, forgeable clue about build time; it is not tamper-proof, an execution time, or an address record." },
  { id:70969, domain:6, level:2, question:"Which behavior would most strongly indicate a keylogger during dynamic analysis?", options:["The sample installs a low-level keyboard hook and writes captured input to a hidden local log file","The sample defragments the hard drive and reports improved read performance back to the user directly","The sample adjusts the desktop resolution to match the connected monitor's native display size setting","The sample synchronizes the system clock with an internet time server on a fixed hourly schedule daily"], correct:0, explanation:"A keyboard hook plus a hidden log points to a keylogger; defragmenting, resolution changes, and clock sync are benign actions." },
  { id:70970, domain:6, level:1, question:"What is a command-and-control (C2) server?", options:["A local antivirus console that manages endpoint definitions across the organization's own workstations","A remote server that an attacker uses to send instructions to and receive data from infected machines","A backup appliance that stores nightly copies of corporate data for disaster recovery purposes only","A patch management server that distributes approved operating system updates to internal client hosts"], correct:1, explanation:"A C2 server directs infected hosts; it is not an antivirus console, a backup appliance, or a patch server." },
  { id:70971, domain:6, level:3, question:"An analyst observes a sample writing to raw physical memory and loading an unsigned driver. What threat class is most consistent?", options:["A simple browser cookie tracker that only records which websites the user has visited most recently","A benign screen recording utility that captures video of the desktop for a training tutorial video","A kernel-mode rootkit attempting to gain Ring 0 access to hide its activity from user-space tools","A standard spell-check dictionary that loads word lists to assist the user while typing documents"], correct:2, explanation:"Raw memory writes and unsigned driver loads indicate a kernel rootkit; a cookie tracker, screen recorder, and spell checker do not operate at that level." },
  { id:70972, domain:6, level:2, question:"Why do investigators capture volatile memory before shutting down a suspected infected machine?", options:["Because the hard drive automatically wipes itself the instant the operating system is shut down cleanly","Because volatile memory is the only place where the master boot record is permanently stored on a host","Because shutting down first would encrypt all user files, making them impossible to recover afterward in this scenario as well.","Because RAM holds running malware, encryption keys, and network connections that vanish once power is lost"], correct:3, explanation:"Volatile memory holds ephemeral evidence lost on power-off; the disk does not self-wipe, the MBR lives on disk, and shutdown does not encrypt files." },
  { id:70973, domain:6, level:2, question:"Which of these is a common ransomware infection vector?", options:["A malicious email attachment or link that, when opened, downloads and executes the ransomware payload","A routine operating system update delivered through the vendor's official and digitally signed channel","A hardware temperature sensor reporting normal readings from inside a properly cooled server chassis","A scheduled antivirus definition refresh that pulls the latest signatures from a trusted mirror server"], correct:0, explanation:"Malicious attachments and links commonly deliver ransomware; official updates, temperature sensors, and AV refreshes are not infection vectors." },
  { id:70974, domain:6, level:1, question:"What is spyware primarily designed to do?", options:["Openly display advertisements that the user has explicitly agreed to view in exchange for free software","Covertly gather information about a user's activity and transmit it to a third party without consent","Automatically back up the user's documents to an encrypted cloud vault for safekeeping every night","Speed up the computer by clearing temporary files and defragmenting the disk on a weekly schedule"], correct:1, explanation:"Spyware secretly collects and exfiltrates data; consented ads, backups, and cleanup utilities are not covert surveillance." },
  { id:70975, domain:6, level:3, question:"A sample resolves API addresses at runtime using GetProcAddress after LoadLibrary. Why does malware commonly do this?", options:["To make the program run measurably faster than if it had linked those functions at compile time normally","To automatically translate the program into another human language for international distribution abroad","To hide its true imports from static analysis, since the functions do not appear in the static import table","To ensure the program is fully compatible with printers manufactured by every major vendor worldwide in this scenario as well."], correct:2, explanation:"Dynamic API resolution hides imports from static tools; it is not primarily about speed, translation, or printer compatibility." },
  { id:70976, domain:6, level:2, question:"What role does threat intelligence play after malware analysis is complete?", options:["It legally prosecutes the attacker directly, bypassing the courts and law enforcement agencies entirely","It physically repairs the damaged hardware components that the malware caused to fail during infection","It guarantees the organization will never be targeted by any cyber attack again in the future at all","It shares extracted IOCs and TTPs so other defenders can detect and block the same threat proactively"], correct:3, explanation:"Threat intelligence disseminates IOCs and TTPs for defense; it does not prosecute, repair hardware, or grant immunity from future attacks." },
  { id:70977, domain:6, level:2, question:"In dark web forensics, what is a 'clearnet leak'?", options:["An instance where hidden service data or the operator's identity becomes exposed on the ordinary internet","A network diagram showing how Tor relays are physically wired together inside a single data center in this scenario as well.","A cleaning utility that automatically wipes browsing history from the Tor Browser after each session","A transparent overlay that displays a website's traffic statistics directly on top of its home page"], correct:0, explanation:"A clearnet leak exposes hidden-service data on the normal internet; it is not a wiring diagram, a history cleaner, or a stats overlay." },
  { id:70978, domain:6, level:1, question:"Which cryptocurrency has historically been most associated with dark web marketplace transactions?", options:["A major national fiat currency issued and fully tracked by a central government banking authority","Bitcoin, which was widely adopted early on despite its transactions being recorded on a public ledger","Airline loyalty reward points, which can only be redeemed for flights through a single carrier program","Physical gold bullion bars, which must be shipped and stored in a secured vault by an armored courier"], correct:1, explanation:"Bitcoin dominated dark web trade despite its public ledger; fiat currency, loyalty points, and gold are not the typical medium." },
  { id:70979, domain:6, level:3, question:"An investigator links a dark web vendor to a real identity by correlating a PGP key reused on a clearnet forum. This relies on what principle?", options:["The fact that all PGP keys legally contain the owner's verified full name and government identity number","The Tor network automatically publishing a mapping of every PGP key to its owner's real IP address in this scenario as well.","Cross-referencing reused artifacts across platforms, since the same key on both sites ties the identities together","A central authority that stores the plaintext private key for every PGP key ever generated anywhere"], correct:2, explanation:"Reused artifacts bridge identities across platforms; PGP keys do not embed legal identities, Tor publishes no key-to-IP map, and no authority stores private keys." },
  { id:70980, domain:6, level:2, question:"What is the purpose of extracting network indicators like domains and IPs from a malware sample?", options:["To calculate the exact monetary profit the attacker earned from operating the malware campaign so far","To determine the physical color of the server rack in the data center hosting the attacker's systems","To automatically refund victims by reversing the fraudulent transactions on their behalf immediately","To enable blocking and detection of the malware's C2 infrastructure across the defended environment"], correct:3, explanation:"Network IOCs let defenders block and detect C2; they do not compute attacker profit, reveal rack colors, or reverse transactions." },
  { id:70981, domain:6, level:2, question:"Which of the following best describes adware?", options:["Software that automatically displays or downloads unwanted advertisements, sometimes bundled with other apps","A kernel rootkit that hides deep in the operating system and never shows any content to the user at all","A ransomware strain that encrypts documents and demands cryptocurrency for their eventual decryption later","A network worm that consumes bandwidth by rapidly replicating across every reachable host on a subnet in this scenario as well."], correct:0, explanation:"Adware pushes unwanted ads; a rootkit hides silently, ransomware encrypts, and a worm replicates, none of which is adware." },
  { id:70982, domain:6, level:1, question:"What is the first phase of a typical malware analysis methodology?", options:["Publicly announcing the malware's full technical details to the press before any analysis is performed","Setting up a safe, isolated analysis environment so the sample cannot escape or contaminate other systems","Immediately deploying the sample to production servers to observe how it behaves under real user load in this scenario as well.","Deleting the sample right away so that it can never accidentally infect the investigator's workstation"], correct:1, explanation:"Analysis starts with a safe isolated lab; announcing prematurely, running in production, or deleting the sample are all wrong first steps." },
  { id:70983, domain:6, level:3, question:"A sample uses process hollowing. Which description matches this technique?", options:["It fills every sector of the hard drive with zeros to securely wipe all data before the analyst arrives","It hollows out a physical hole in the server chassis to hide a small wireless exfiltration device inside","It starts a legitimate process suspended, replaces its memory with malicious code, then resumes execution","It removes all comments from the malware's source code to make it smaller and slightly harder to read in this scenario as well."], correct:2, explanation:"Process hollowing swaps a suspended process's memory for malicious code; it is not disk wiping, physical tampering, or comment stripping." },
  { id:70984, domain:6, level:2, question:"Why might an analyst use a network simulation tool like INetSim during dynamic analysis?", options:["To physically cut the power to the analysis machine the moment any suspicious behavior is detected","To automatically translate the malware's network traffic into the analyst's preferred spoken language","To permanently encrypt the malware sample so it can never be executed a second time on the host","To provide fake services so the malware attempts C2 communication without reaching the real internet"], correct:3, explanation:"INetSim fakes internet services to safely observe C2 attempts; it does not cut power, translate speech, or encrypt samples." },
  { id:70985, domain:6, level:2, question:"What does 'defanging' an IOC mean when documenting malware findings?", options:["Rewriting URLs and IPs in a harmless form, like hxxp, so readers cannot accidentally click or execute them","Removing the malware's ability to run by deleting a specific function from its compiled binary code in this scenario as well.","Encrypting the report so that only investigators with the correct password can read the IOC list at all","Physically destroying the storage media on which the malware sample was originally discovered and stored"], correct:0, explanation:"Defanging neutralizes IOC formatting to prevent accidental activation; it is not code editing, report encryption, or media destruction." },
  { id:70986, domain:6, level:1, question:"Which of the following is a behavioral (dynamic) indicator rather than a static one?", options:["The sample's file size on disk is exactly two hundred and fifty six kilobytes when measured at rest","The sample creates a new service and beacons to an external server shortly after it begins executing","The sample's PE header lists a particular compile timestamp that was recorded when it was first built","The sample contains a specific embedded string visible when the file is scanned with the strings tool"], correct:1, explanation:"Creating a service and beaconing are runtime behaviors; file size, compile timestamp, and embedded strings are static attributes." },
  { id:70987, domain:6, level:3, question:"An analyst wants to determine if two different-looking samples belong to the same family. Which approach is most appropriate?", options:["Checking whether the two files have the identical exact size in bytes, which alone proves shared lineage","Confirming both files were downloaded on the same calendar day, which conclusively links their authorship","Comparing code structure with fuzzy hashing like ssdeep and shared YARA signatures across the samples","Verifying that both files use the same icon image, which by itself guarantees a common malware family"], correct:2, explanation:"Fuzzy hashing and shared signatures reveal code similarity; identical size, download date, or icon do not reliably prove a shared family." },
  { id:70988, domain:6, level:2, question:"What is a common goal of malware that disables or terminates antivirus processes on infection?", options:["To free up disk space by uninstalling unused security software the user no longer wishes to keep around","To improve overall system performance for the user by stopping resource-intensive background scans now","To comply with a corporate policy that requires only a single security product to run at any one time","To remove endpoint defenses so it can operate and persist without being detected or blocked by the AV"], correct:3, explanation:"Killing AV removes defenses so the malware runs freely; it is not disk cleanup, performance tuning, or policy compliance." },
  { id:70989, domain:6, level:2, question:"Which registry-based artifact can reveal programs configured to run at startup, useful for finding persistence?", options:["The Run keys, Winlogon entries, and services keys, which malware frequently abuses to survive reboots","The wallpaper slideshow interval setting, which only controls how often the desktop background rotates","The mouse pointer speed value, which merely adjusts how quickly the cursor moves across the screen","The default web browser association, which simply records which browser opens when links are clicked"], correct:0, explanation:"Run keys, Winlogon, and services enable autostart persistence; wallpaper timing, mouse speed, and browser association do not." },
  { id:70990, domain:6, level:1, question:"What does the acronym RAT stand for in malware analysis?", options:["Rapid Antivirus Test, a benchmark that measures how quickly a scanner can inspect a large hard drive","Remote Access Trojan, a program giving an attacker covert remote control over an infected computer","Redundant Array of Tapes, a backup configuration that stripes data across several magnetic tape drives","Registered Application Token, a credential issued to trusted software during a licensing activation step"], correct:1, explanation:"RAT means Remote Access Trojan; the other expansions are invented and unrelated to malware." },
  { id:70991, domain:6, level:3, question:"You recover a memory image and want to list network connections that existed at capture time. Which analysis is appropriate?", options:["Reading the connections from the printed hard-copy manual that shipped with the computer originally","Inferring the connections purely from the color of the status LED on the front of the network switch","Using a memory forensics tool to parse the network connection structures preserved in the RAM image","Guessing the connections from how warm the network cable felt when it was unplugged from the host"], correct:2, explanation:"Memory tools parse connection structures from RAM; manuals, LED colors, and cable warmth provide no such data." },
  { id:70992, domain:6, level:2, question:"What makes cryptocurrency attractive to ransomware operators despite blockchain being public?", options:["It automatically hides every transaction from the public ledger so no investigator can ever see them at all","It legally guarantees that no law enforcement agency anywhere is permitted to investigate the payments in this scenario as well.","It refunds the victim automatically if the attacker fails to deliver the promised decryption key in time","It enables pseudonymous, borderless payments that are difficult, though not impossible, to attribute to a person"], correct:3, explanation:"Crypto offers pseudonymous cross-border payment; it does not hide the ledger, grant legal immunity, or auto-refund victims." },
  { id:70993, domain:6, level:2, question:"A scheduled task points to a PowerShell command that downloads and runs code from a URL. This is characteristic of what?", options:["A fileless or staged malware persistence and delivery mechanism abusing a trusted native scripting tool","A routine Windows Update task that Microsoft installs by default on every supported version of Windows","A standard disk cleanup job that removes temporary files from the system on a regular weekly cadence","A harmless screensaver configuration that changes the lock screen image at a set interval automatically"], correct:0, explanation:"PowerShell downloading and running remote code is fileless malware delivery; it is not Windows Update, disk cleanup, or a screensaver setting." },
  { id:70994, domain:6, level:1, question:"What is the safest way to handle a live malware sample during transfer between analysts?", options:["Email it as a plain unprotected executable attachment so recipients can run it immediately on opening","Store it in a password-protected, encrypted archive clearly labeled as malicious to prevent accidental execution","Copy it onto the shared production file server so every employee has convenient access to the sample in this scenario as well.","Rename it to look like a system file and place it in the Windows startup folder for easy retrieval later"], correct:1, explanation:"Encrypted, labeled archives prevent accidental detonation; plain attachments, shared servers, and startup-folder placement are dangerous." },
  { id:70995, domain:6, level:3, question:"A sample contains base64-encoded strings that decode into a second-stage script. Why do attackers commonly use base64 here?", options:["Because base64 is the only encoding capable of representing script text inside an executable file at all","Because base64 automatically compresses the payload to less than one percent of its original file size in this scenario as well.","To obscure the payload from casual inspection and simple signature scanners until it is decoded at runtime","Because base64 encryption is mathematically unbreakable and fully protects the payload from any analyst"], correct:2, explanation:"Base64 obscures payloads from casual scanning; it is not the only text encoding, does not meaningfully compress, and is encoding not encryption." },
  { id:70996, domain:6, level:2, question:"Which of the following is TRUE about Tor bridges?", options:["They are public servers that broadcast the real IP of every Tor user to any observer on the network in this scenario as well.","They are physical fiber links owned by a single company that controls all traffic on the Tor network","They are decryption devices that automatically remove all anonymity from Tor traffic passing through them","They are unlisted relays that help users connect to Tor where access to public relays is blocked or censored"], correct:3, explanation:"Bridges are unlisted entry relays for censored users; they do not broadcast user IPs, are not company-owned links, and do not strip anonymity." },
  { id:70997, domain:6, level:2, question:"During a ransomware investigation, why is identifying the specific ransomware family important?", options:["It may reveal whether a free decryptor exists and clarifies the expected behavior and IOCs for containment","It legally compels the attacker to release the decryption key within a fixed number of business days","It automatically restores all encrypted files from the ransomware's own built-in backup of the originals","It physically prevents the encryption process from ever starting again on any computer in the world in this scenario as well."], correct:0, explanation:"Family identification can point to decryptors and known IOCs; it does not compel attackers, restore files automatically, or globally stop encryption." },
  { id:70998, domain:6, level:1, question:"What is a hash collision in the context of file identification?", options:["When two identical copies of the same file are stored in two different folders on the same disk volume","When two different files produce the same hash value, which weak algorithms like MD5 are vulnerable to","When a hard drive's read head physically strikes the platter surface and damages the stored data","When two network packets arrive at the same switch port at the exact same nanosecond and are dropped"], correct:1, explanation:"A collision is two distinct files sharing a hash; it is not duplicate storage, a physical head crash, or a network packet event." },
  { id:70999, domain:6, level:3, question:"A sample queries a disk enumeration registry key and finds strings like VMWARE or VBOX. What is the sample doing?", options:["Optimizing its storage driver so the malware can read and write to the disk at maximum possible speed","Registering itself as a legitimate signed disk device driver approved by the hardware manufacturer","Detecting a virtual machine so it can alter or halt its behavior to evade the analysis environment","Backing up the disk enumeration data so the user can restore their drive configuration after a crash"], correct:2, explanation:"Reading VM-identifying registry strings is VM detection for evasion; it is not driver optimization, driver registration, or backup." },
  { id:71000, domain:6, level:2, question:"What is the primary investigative value of collecting a full packet capture during malware execution?", options:["It automatically identifies the attacker's home address from the metadata contained in the captured packets","It permanently blocks all future connections to the malicious server without any additional configuration","It converts the malware into a harmless form simply by observing its traffic as it flows across the wire","It records the exact bytes exchanged with C2, enabling protocol reconstruction and IOC extraction later"], correct:3, explanation:"Full packet capture allows protocol reconstruction and IOC extraction; it does not reveal home addresses, block traffic, or neutralize malware." },
  { id:71001, domain:6, level:2, question:"Which of these describes a supply chain malware attack?", options:["Compromising a trusted software vendor so malicious code is distributed to customers through legitimate updates","Sending a phishing email directly to a single end user hoping they open a malicious attachment themselves","Physically stealing a laptop from an employee's car to extract the sensitive data stored on its hard drive","Guessing a weak administrator password through repeated automated login attempts against a public server in this scenario as well."], correct:0, explanation:"Supply chain attacks poison trusted vendor distribution; phishing, laptop theft, and password guessing are different attack types." },
  { id:71002, domain:6, level:1, question:"What is the role of an antivirus signature?", options:["A handwritten legal endorsement the software vendor adds to prove the antivirus license is authentic","A pattern that uniquely identifies known malware, allowing scanners to detect matching files quickly","A network protocol that securely transmits video conferencing streams between two remote offices","A backup schedule that determines how often user documents are copied to an external storage device"], correct:1, explanation:"A signature is a detection pattern for known malware; it is not a legal endorsement, a video protocol, or a backup schedule." },
  { id:71003, domain:6, level:3, question:"A malware sample uses domain fronting for its C2 traffic. What advantage does this give the attacker?", options:["It doubles the speed of the C2 channel by splitting the connection across two separate internet providers in this scenario as well.","It guarantees the malware will run only on computers located within one specific target country's borders","It hides the true C2 destination behind a reputable domain, making the traffic appear to go to a trusted CDN","It automatically deletes the malware after the attacker finishes exfiltrating the victim's sensitive data"], correct:2, explanation:"Domain fronting masks the real C2 behind a trusted domain; it is not about speed, geo-restriction, or self-deletion." },
  { id:71004, domain:6, level:2, question:"Why do investigators use write blockers when analyzing storage that may contain malware evidence?", options:["To physically speed up read operations so the forensic image can be captured in a much shorter time","To automatically decrypt any ransomware-encrypted files stored on the media before imaging begins in this scenario as well.","To install fresh antivirus software directly onto the suspect drive before the analysis is performed","To prevent any modification of the original evidence media, preserving its integrity for court admissibility"], correct:3, explanation:"Write blockers preserve evidence integrity by preventing writes; they do not speed reads, decrypt files, or install software." },
  { id:71005, domain:6, level:2, question:"What does the term 'staged payload' mean in malware delivery?", options:["The initial component downloads a larger second stage, splitting delivery to reduce the initial footprint","The entire malware is delivered as one enormous file so nothing else needs to be downloaded later on in this scenario as well.","The payload is performed live on a theater stage as a demonstration for a security awareness audience","The malware waits on a shelf in a warehouse until it is physically shipped to the target organization"], correct:0, explanation:"A staged payload fetches a later stage to stay small initially; it is not a single monolithic file, a stage performance, or physical shipping." },
  { id:71006, domain:6, level:1, question:"Which of the following best defines 'exfiltration' in a malware incident?", options:["The routine nightly backup of corporate files to an approved and encrypted cloud storage provider now","The unauthorized transfer of data from the victim's environment out to an attacker-controlled destination","The installation of a security patch that closes the vulnerability the malware originally exploited in this scenario as well.","The defragmentation of a fragmented hard drive to consolidate scattered file fragments for more speed"], correct:1, explanation:"Exfiltration is unauthorized outbound data theft; it is not authorized backup, patching, or defragmentation." },
  { id:71007, domain:6, level:3, question:"A sample only executes its payload if a specific mutex does NOT already exist. What is the purpose of this check?", options:["It verifies the antivirus is running before the malware agrees to execute its intended malicious payload","It ensures the victim has paid the ransom in full before any of the encrypted files will be released","It prevents multiple concurrent infections on the same host, a common self-management behavior in malware","It confirms the analyst has signed a legal waiver granting permission for the malware to run at all in this scenario as well."], correct:2, explanation:"The mutex check avoids duplicate infections; it is not an AV check, a payment gate, or a legal waiver." },
  { id:71008, domain:6, level:2, question:"What is the significance of the Import Address Table (IAT) in a PE file during analysis?", options:["It stores the complete decrypted ransom note that will be shown to the victim once encryption finishes","It contains the attacker's private cryptocurrency wallet seed phrase embedded in plaintext for recovery","It records the physical serial numbers of every hardware component installed in the infected computer in this scenario as well.","It lists the external functions the binary calls, offering strong hints about the malware's capabilities"], correct:3, explanation:"The IAT reveals imported functions and hints at capability; it is not a ransom note, a wallet seed, or a hardware serial list." },
  { id:71009, domain:6, level:2, question:"Which is a legitimate concern when relying solely on VirusTotal detection ratios?", options:["A low detection count does not guarantee a file is safe, since new or targeted malware may evade all engines","A high detection count legally proves the exact identity of the human author who created the malware in this scenario as well.","The detection ratio automatically remediates every infected endpoint the moment the file is uploaded","The detection ratio physically prevents the sample from ever executing again on the analyst's machine"], correct:0, explanation:"Low detection is not proof of safety; the ratio does not identify authors, remediate endpoints, or block execution." },
  { id:71010, domain:6, level:1, question:"What is a hidden service in the Tor network?", options:["A publicly indexed website that any search engine can crawl and that resolves through normal DNS","A server whose location is concealed and which is reachable only via its .onion address through Tor","A hardware firewall appliance that filters inbound traffic at a corporate network's outer perimeter","A cloud backup service that stores encrypted copies of user files across multiple global data centers"], correct:1, explanation:"A Tor hidden service hides its location behind a .onion address; it is not a public indexed site, a firewall, or a backup service." },
  { id:71011, domain:6, level:3, question:"An investigator seizes a suspect's computer running a Tor hidden service. Why is capturing live memory before shutdown critical?", options:["The hard drive will physically catch fire the moment the operating system is shut down normally by anyone","Shutting down first automatically uploads all evidence to the attacker's server across the internet at once","RAM may hold the service's private keys, active connections, and configuration that are lost once powered off","The Tor Browser will email the suspect a warning that their machine is being investigated by the police in this scenario as well."], correct:2, explanation:"Live memory can hold keys and connection state lost on shutdown; the disk does not ignite, shutdown does not upload evidence, and Tor sends no warnings." },
  { id:71012, domain:6, level:2, question:"What is the purpose of correlating malware IOCs with the MITRE ATT&CK framework?", options:["It automatically arrests the attacker by transmitting the technique IDs directly to law enforcement systems","It replaces the need for any antivirus software because ATT&CK blocks all mapped techniques by itself now","It converts the malware sample into a benign training file suitable for use in awareness presentations in this scenario as well.","It maps observed behaviors to named techniques, helping communicate the threat and improve defensive coverage"], correct:3, explanation:"ATT&CK mapping standardizes and communicates behaviors for defense; it does not arrest attackers, replace AV, or neutralize samples." },
  { id:71013, domain:6, level:2, question:"Which statement about ransomware-as-a-service (RaaS) is accurate?", options:["Developers lease ransomware to affiliates who deploy it, splitting proceeds and lowering the skill barrier","It is a legitimate cloud backup subscription that protects businesses from losing data to ransomware attacks","It is an antivirus feature that automatically decrypts files after any ransomware infection occurs on a host","It is a government program that reimburses victims for ransom payments made to cyber criminals in full"], correct:0, explanation:"RaaS leases malware to affiliates for a cut; it is not a backup subscription, an AV feature, or a government reimbursement program." },
  { id:71014, domain:6, level:1, question:"What does 'obfuscation' mean when applied to malware code?", options:["Formally documenting every function of the code so future analysts can understand it much more quickly","Deliberately making the code harder to read or analyze while preserving its original malicious function","Compiling the code so it runs faster on the target processor without changing any of its behavior at all","Digitally signing the code with a trusted certificate to prove which vendor legitimately produced it"], correct:1, explanation:"Obfuscation deliberately hinders analysis; it is not documentation, performance compilation, or code signing." },
  { id:71015, domain:6, level:3, question:"A sample writes itself into the Alternate Data Stream of a legitimate NTFS file. Why is this technique used?", options:["ADS automatically encrypts the malware with an unbreakable cipher that no forensic tool can ever recover","ADS makes the malware run at kernel privilege level without needing to exploit any vulnerability at all in this scenario as well.","ADS content is hidden from ordinary directory listings, helping the malware conceal itself from casual view","ADS guarantees the file survives a complete low-level format and reinstallation of the operating system"], correct:2, explanation:"ADS hides data from normal listings; it does not encrypt content, grant kernel rights, or survive a full format." },
  { id:71016, domain:6, level:2, question:"Which behavior during analysis would suggest a sample is attempting data exfiltration?", options:["The sample reduces the monitor brightness to conserve battery power on a laptop during idle periods now","The sample plays a startup chime through the speakers when the operating system finishes booting up in this scenario as well.","The sample rearranges the desktop icons alphabetically to help the user find their programs more easily","The sample compresses local documents and uploads them to an unfamiliar external server over the network"], correct:3, explanation:"Compressing and uploading files to an external server indicates exfiltration; brightness, chimes, and icon sorting are benign." },
  { id:71017, domain:6, level:2, question:"What is the benefit of using a dedicated, network-isolated 'malware lab' virtual machine?", options:["It contains the sample so it cannot spread to production systems or reach the internet during analysis","It legally transfers ownership of the malware to the analyst, who can then sell it to other researchers","It automatically writes the final incident report and submits it to management without analyst effort","It permanently immunizes every other computer on the corporate network against that malware family"], correct:0, explanation:"An isolated lab contains the sample safely; it does not transfer ownership, write reports, or immunize other machines." },
  { id:71018, domain:6, level:1, question:"What is a 'variant' of a malware family?", options:["A completely unrelated program that happens to share only its file name with the original malware","A modified version of existing malware that shares core code or behavior but differs in some details","The legitimate antivirus tool specifically built to remove one particular strain of that malware","A hardware component that the malware requires to be physically installed before it can execute in this scenario as well."], correct:1, explanation:"A variant is a modified relative of the family sharing core traits; it is not an unrelated program, an AV tool, or hardware." },
  { id:71019, domain:6, level:3, question:"An analyst observes API calls to VirtualAllocEx, WriteProcessMemory, and CreateRemoteThread. What technique do these strongly indicate?", options:["A routine memory defragmentation performed by the operating system to reclaim fragmented heap space in this scenario as well.","A standard file copy operation moving a document from one folder to another on the same disk volume","Code injection into a remote process, allocating memory in it, writing the payload, then starting a thread","A benign screen brightness adjustment triggered when the ambient light sensor detects a darker room"], correct:2, explanation:"That API sequence is classic remote code injection; it is not defragmentation, a file copy, or a brightness adjustment." },
  { id:71020, domain:6, level:2, question:"Why is understanding a malware's C2 protocol useful for creating network detection signatures?", options:["It allows the antivirus to physically unplug the network cable whenever the malware attempts to beacon out","It converts the malware's encrypted traffic into plaintext automatically without needing any decryption keys","It guarantees the attacker's server will be legally shut down by the hosting provider within just one hour","Recognizing the protocol's patterns lets defenders write IDS rules that flag matching traffic on the network"], correct:3, explanation:"Protocol patterns enable IDS signatures; they do not unplug cables, magically decrypt traffic, or force takedowns." },
  { id:71021, domain:6, level:2, question:"What is 'threat hunting' in relation to malware and IOCs?", options:["Proactively searching an environment for signs of compromise using hypotheses, IOCs, and behavioral analytics","Waiting passively for an antivirus alert to fire before taking any investigative action at all whatsoever","Physically inspecting each employee's desk for printed passwords left out in the open near their computer","Automatically paying any ransom demand as soon as a suspicious file is detected on a corporate endpoint in this scenario as well."], correct:0, explanation:"Threat hunting is proactive searching for compromise; it is not passive alert-waiting, desk inspection, or paying ransoms." },
  { id:71022, domain:6, level:1, question:"Which of the following is an example of a persistence mechanism on Windows?", options:["Increasing the display refresh rate so the screen updates more smoothly during fast-moving video now","Adding a program path to a Run registry key so it launches automatically each time the user logs in","Changing the default printer so documents route to a different device on the office network by default","Adjusting the system volume so notification sounds play at a comfortable level for the working user"], correct:1, explanation:"A Run key entry provides autostart persistence; refresh rate, default printer, and volume settings do not persist malware." },
  { id:71023, domain:6, level:3, question:"A sample sends outbound DNS TXT record queries containing encoded data to a domain it controls. What technique is this?", options:["A standard reverse DNS lookup that every ordinary application performs when resolving a hostname to an IP","A benign dynamic DNS update that a home router sends to keep its changing public address registered","DNS tunneling, using DNS queries and responses as a covert channel to exfiltrate data or reach C2","A routine DNSSEC validation step that cryptographically verifies the authenticity of a DNS response"], correct:2, explanation:"Encoded data in TXT queries is DNS tunneling for covert C2/exfiltration; it is not reverse lookup, dynamic DNS, or DNSSEC validation." },
  { id:71024, domain:6, level:2, question:"When triaging a suspicious file, why is submitting only the hash (not the file) to a public service sometimes preferred?", options:["It runs the full file inside the analyst's own browser tab so results appear faster than uploading it","It legally transfers responsibility for the investigation to the public service that receives the hash","It automatically decrypts the file so the analyst can read its contents without any further steps in this scenario as well.","It avoids exposing potentially sensitive or targeted sample contents publicly while still checking reputation"], correct:3, explanation:"Sharing only the hash protects sensitive contents while checking reputation; it does not run the file, transfer liability, or decrypt anything." },
  { id:71025, domain:6, level:2, question:"What is a common characteristic of banking trojans such as those in the Zeus lineage?", options:["They inject into browser sessions to steal credentials and manipulate online banking transactions covertly","They openly display their presence with a large banner asking the user to donate to the malware author","They only affect offline calculators and have no ability to interact with any web browser at all ever","They are officially distributed by banks to help customers protect their online accounts from fraud in this scenario as well."], correct:0, explanation:"Banking trojans hook browsers to steal banking credentials; they do not announce themselves, ignore browsers, or come from banks." },
  { id:71026, domain:6, level:1, question:"What does 'triage' mean in the malware investigation workflow?", options:["Permanently deleting every suspicious file immediately without recording any information about it first","Quickly assessing and prioritizing samples to decide which need deeper analysis and how urgent each is","Physically sorting the organization's computers by their manufacturer and model before analysis begins","Automatically paying ransoms in the order the infections were first reported to the help desk team"], correct:1, explanation:"Triage prioritizes samples for further analysis; it is not mass deletion, hardware sorting, or ordered ransom payment." },
  { id:71027, domain:6, level:3, question:"Why does reflective DLL injection (a memory-only DLL never written to disk) complicate forensics?", options:["The DLL prints its full source code to the screen, making disk analysis the only reliable method available","The DLL automatically emails a copy of itself to the investigator, removing the need for any analysis at all","The DLL never touches disk, so traditional file-based scanning misses it and memory capture becomes essential","The DLL can only be recovered from the printer spooler queue, which retains a copy of every loaded module in this scenario as well."], correct:2, explanation:"Reflective injection leaves nothing on disk, requiring memory forensics; it does not print source, email itself, or reside in the spooler." },
  { id:71028, domain:6, level:2, question:"Which of the following is a valid reason to analyze malware in both static and dynamic ways?", options:["Static and dynamic analysis always produce the exact same output, so doing both simply wastes analyst time","Dynamic analysis is illegal, so static analysis must always be performed first to obtain legal permission","Static analysis physically repairs infected files while dynamic analysis reinstalls the operating system in this scenario as well.","Static analysis reveals structure safely while dynamic analysis confirms actual behavior, complementing each other"], correct:3, explanation:"The two methods complement each other; they do not produce identical output, dynamic analysis is not illegal, and neither repairs files." },
  { id:71029, domain:6, level:2, question:"What is the significance of finding a hardcoded C2 domain that uses a dynamic DNS provider?", options:["It lets the attacker change the resolved IP quickly, so defenders should track the domain rather than a single IP","It proves the malware is harmless because dynamic DNS providers only serve legitimate business customers in this scenario as well.","It means the domain can never be blocked because dynamic DNS records are legally protected from filtering","It guarantees the attacker's real name is listed in the dynamic DNS provider's public registration records"], correct:0, explanation:"Dynamic DNS lets attackers rotate IPs, so track the domain; it does not prove innocence, prevent blocking, or expose the attacker's name." },
  { id:71030, domain:6, level:1, question:"What is a common purpose of packing an executable?", options:["To add helpful inline comments throughout the code so future maintainers understand it more easily now","To compress and obscure the code so it is smaller and harder to analyze or detect by signature scanners","To ensure the program prints a detailed usage manual to the console every single time it is executed","To translate the program's user interface text into several human languages for global distribution in this scenario as well."], correct:1, explanation:"Packing compresses and obscures code to hinder analysis; it does not add comments, print manuals, or translate interfaces." },
  { id:71031, domain:6, level:3, question:"A sample terminates immediately if the logged-in username is 'sandbox' or 'malware'. This behavior is an example of what?", options:["A licensing restriction that only permits the software to run for users whose names appear on an allow list","An accessibility setting that adjusts the interface based on the currently logged-in account's preferences","Environment-aware evasion, checking for analyst usernames that commonly indicate an analysis sandbox host","A parental control feature that blocks the program for accounts flagged as belonging to minors on the host"], correct:2, explanation:"Checking for analyst-style usernames is sandbox evasion; it is not licensing, accessibility, or parental controls." },
  { id:71032, domain:6, level:2, question:"Why might a malware sample check its own filename before executing its payload?", options:["Filenames are legally required to match the payload, so the malware verifies compliance before running it","The filename contains the decryption key, so the malware must read it to unlock its own encrypted payload","Checking the filename physically speeds up the disk read so the payload loads into memory much faster","Some sandboxes rename samples to their hash, so a mismatch tips the malware off that it is being analyzed"], correct:3, explanation:"Renamed samples reveal a sandbox, so the check is evasion; filenames are not legally mandated, key stores, or speed factors." },
  { id:71033, domain:6, level:2, question:"What is the investigative purpose of extracting configuration data (like C2 lists) embedded in malware?", options:["It reveals the attacker infrastructure and campaign scope, informing blocking, hunting, and attribution efforts","It automatically shuts down every server in the configuration by transmitting a remote kill command to them in this scenario as well.","It refunds the victims listed in the configuration by reversing the fraudulent charges against their accounts","It legally seizes the attacker's assets the moment the configuration is decoded by the analysis team members"], correct:0, explanation:"Config extraction exposes infrastructure for defense; it does not kill servers, refund victims, or seize assets." },
  { id:71034, domain:6, level:1, question:"Which of the following describes a 'zero-day' in the context of malware?", options:["Malware that is exactly zero bytes in size and therefore cannot contain any executable code at all","Malware that exploits a vulnerability unknown to the vendor, for which no patch is yet available","Malware that only activates on the first day of the calendar year and remains fully dormant otherwise","Malware that has already been fully patched by the vendor and can no longer infect any modern system"], correct:1, explanation:"A zero-day exploits an unpatched unknown flaw; it is not a zero-byte file, a New Year trigger, or already-patched code." },
  { id:71035, domain:6, level:3, question:"An analyst wants to attribute a malware campaign. Which combination of evidence provides the strongest support?", options:["A single reused stock icon image, which by itself definitively proves who authored the entire campaign","The calendar day of the week on which each sample was first seen, which alone identifies the attacker in this scenario as well.","Overlapping code, shared infrastructure, and consistent TTPs correlated across multiple related incidents","The color scheme of the ransom note, which conclusively names the specific criminal group responsible"], correct:2, explanation:"Multiple overlapping technical and behavioral signals support attribution; an icon, weekday, or note color alone is far too weak." },
  { id:71036, domain:6, level:2, question:"What is a realistic limitation of automated sandbox analysis?", options:["Sandboxes are physically incapable of running any Windows executable, so all analysis must be done manually","Automated sandboxes always identify the attacker's home address as part of their standard report output now","Sandboxes permanently cure the analyst's entire network of every infection simply by running one sample","Malware may detect the sandbox or wait out its short runtime, so it never reveals its full behavior there"], correct:3, explanation:"Evasion and short runtimes limit sandboxes; they can run executables, do not reveal home addresses, and do not cure networks." },
  { id:71037, domain:6, level:2, question:"Which of the following is an anti-forensic technique malware might use?", options:["Clearing Windows event logs and timestomping files to disrupt the timeline investigators try to build","Writing a detailed, accurate audit log of every action it takes so investigators can follow along easily","Displaying a clear on-screen banner announcing exactly which files it has modified and encrypted so far","Automatically preserving pristine backups of every file it touches for the forensic team to recover later"], correct:0, explanation:"Log clearing and timestomping are anti-forensic; accurate logging, announcements, and backups would aid, not hinder, investigators." },
  { id:71038, domain:6, level:1, question:"Malicious-document payload delivery usually relies on tricking the user into doing what?", options:["A hardware defect in the keyboard that randomly types commands into the terminal without user input","Enabling macros or embedded content so the hidden code executes and pulls down the malware payload","The document physically overheating the processor until it executes arbitrary instructions on its own","A guarantee from the vendor that all documents are automatically safe to open with any content enabled"], correct:1, explanation:"Malicious documents rely on users enabling macros/content; not keyboard defects, overheating, or vendor guarantees." },
  { id:71039, domain:6, level:3, question:"A sample creates a WMI event subscription that triggers a script on system events. Why is this notable to an investigator?", options:["WMI subscriptions are purely cosmetic and only change the color of icons displayed in the system tray now","WMI subscriptions can only be created by the operating system itself and never by any third-party code","WMI event subscriptions are a stealthy, fileless persistence method that evades many file-based detections","WMI subscriptions automatically expire within sixty seconds and therefore cannot provide persistence at all"], correct:2, explanation:"WMI event subscriptions provide stealthy fileless persistence; they are not cosmetic, OS-exclusive, or auto-expiring." },
  { id:71040, domain:6, level:2, question:"What is the purpose of comparing pre-infection and post-infection registry snapshots?", options:["It automatically rolls the entire system back in time to before the infection without any analyst action in this scenario as well.","It encrypts the registry so the malware can no longer read any of the keys it needs to operate correctly","It physically replaces the registry hive files with copies downloaded from the software vendor's website","It isolates exactly which registry keys the malware added or modified, revealing persistence and configuration"], correct:3, explanation:"Snapshot comparison reveals malware's registry changes; it does not auto-rollback, encrypt the registry, or swap hive files." },
  { id:71041, domain:6, level:2, question:"Which statement about cryptocurrency mixing services and law enforcement is most accurate?", options:["Mixers hinder tracing, but advanced chain analysis and exchange cooperation can sometimes still follow the funds","Mixers make tracing completely impossible, so no cryptocurrency has ever been recovered by investigators","Mixers are operated exclusively by governments to help investigators trace criminal funds more easily now","Mixers automatically report every user's identity to law enforcement as a legal condition of operating in this scenario as well."], correct:0, explanation:"Mixers hinder but do not always defeat tracing; they are not government-run tracing aids and do not report users." },
  { id:71042, domain:6, level:1, question:"What is a 'sample' in malware analysis terminology?", options:["A demonstration antivirus product distributed for free so customers can try its features before buying","A specific instance of suspected malicious code obtained for examination in the analysis environment","A physical swab taken from an infected computer's surface to test for biological contamination on it","A survey sent to employees asking whether they have noticed any unusual behavior on their computers"], correct:1, explanation:"A sample is a suspected malicious code instance for analysis; it is not a trial antivirus, a physical swab, or a survey." },
  { id:71043, domain:6, level:3, question:"A ransomware appends a unique extension and drops a note in every folder. How does this help family identification?", options:["The extension physically changes the file system type of the disk, which uniquely identifies the attacker","The note contains the attacker's fingerprints in a literal biometric sense that police can match directly","The extension and note format are often distinctive fingerprints that map to a known ransomware family","The extension automatically decrypts itself after seven days, proving which family generated it originally"], correct:2, explanation:"Distinctive extensions and note formats fingerprint families; they do not change filesystem type, hold biometrics, or self-decrypt." },
  { id:71044, domain:6, level:2, question:"Why is it important to document the chain of custody for a malware sample used as evidence?", options:["It automatically converts the malware into a harmless form once the final signature is added to the log in this scenario as well.","It guarantees the malware will never be analyzed by anyone outside the original investigation team ever","It physically encrypts the sample so that only the person who signed the log first can open the file again","It records every handler and transfer so the evidence remains admissible and defensible in legal proceedings"], correct:3, explanation:"Chain of custody preserves admissibility by tracking handling; it does not neutralize malware, restrict analysis, or encrypt the file." },
  { id:71045, domain:6, level:2, question:"What does a high number of anti-VM and anti-debug checks in a sample generally suggest about it?", options:["The author invested effort to resist analysis, often implying a more sophisticated or targeted threat","The sample is certainly harmless, because only legitimate software ever bothers to check for debuggers now","The sample can only run inside a virtual machine and will refuse to execute on any physical hardware at all","The sample is guaranteed to be a false positive that no antivirus engine should ever flag as malicious"], correct:0, explanation:"Heavy anti-analysis suggests a determined, capable author; it does not indicate benign software, VM-only execution, or a false positive." },
  { id:71046, domain:6, level:1, question:"Which of the following is TRUE about ransomware decryption keys?", options:["Any ransomware's files can always be decrypted instantly with a single universal master key that exists","Without the correct key, strongly encrypted files generally cannot be recovered except from clean backups","Rebooting the infected machine several times reliably reverses the encryption and restores every file","Renaming the encrypted files back to their original names fully restores their original readable contents"], correct:1, explanation:"Strong encryption requires the key or backups; there is no universal master key, and rebooting or renaming does not decrypt files." },
  { id:71047, domain:6, level:3, question:"A sample communicates over a peer-to-peer protocol rather than a single central C2. What advantage does this give the attacker?", options:["P2P legally prevents authorities from investigating any node because the traffic is peer-to-peer by nature","P2P automatically encrypts every victim's files without the malware needing any separate ransomware module","P2P removes a single point of failure, making the botnet resilient to takedown of any one node or server","P2P guarantees the botnet will double in size every single day regardless of how many nodes defenders remove"], correct:2, explanation:"P2P adds resilience against takedowns; it does not confer legal immunity, encrypt files by itself, or guarantee growth." },
  { id:71048, domain:6, level:2, question:"What is the role of a 'detonation' environment in malware analysis?", options:["A production server chosen specifically so the malware's real-world impact can be measured on live users","A physical blast chamber used to destroy the storage media after the malware has been fully analyzed","A cloud billing dashboard that tracks how much the attacker spent to develop and deploy the malware","A controlled, isolated system where the sample is executed on purpose to safely observe its behavior"], correct:3, explanation:"A detonation environment safely runs malware to observe it; it is not a production server, a blast chamber, or a billing dashboard." },
  { id:71049, domain:6, level:2, question:"Why do investigators hash evidence files both before and after analysis?", options:["Matching hashes prove the evidence was not altered during handling, supporting its integrity in court later","Different hashes automatically identify which antivirus engine detected the malware sample first in the queue","Hashing twice speeds up the analysis by caching the file's contents in the processor for faster reads later","The second hash decrypts any encrypted sections that the first hash was unable to process fully at the time"], correct:0, explanation:"Before/after hash matching proves integrity; it does not identify AV engines, speed analysis, or decrypt content." },
  { id:71050, domain:6, level:1, question:"What is 'lateral movement' in a malware-driven intrusion?", options:["The attacker physically relocating the compromised server to a different rack in the data center","The attacker moving from an initially compromised host to other systems within the same network","The user dragging a window sideways across the screen from one monitor to an adjacent display","The antivirus scanning files in alphabetical order across the disk during a scheduled full system scan"], correct:1, explanation:"Lateral movement is spreading to other internal systems; it is not moving hardware, dragging windows, or ordered scanning." },
  { id:71051, domain:6, level:3, question:"A sample decrypts its second stage with a key derived from the host's hardware. Why use a hardware-derived key?", options:["It ensures the payload runs faster because hardware-derived keys are processed directly by the CPU cache","It makes the sample legally impossible to analyze, since hardware keys are protected by intellectual property","It ties the payload to a specific target, so the sample will not decrypt or run in an analyst's environment","It automatically uploads the decrypted payload to the vendor for a free second opinion on its behavior now"], correct:2, explanation:"Hardware-tied keys prevent decryption outside the target, defeating analysis; they are not about speed, legality, or vendor uploads." },
  { id:71052, domain:6, level:2, question:"Which of the following would most help an investigator identify a dark web marketplace vendor's shipping origin?", options:["Reading the vendor's verified home address, which every dark web marketplace publicly displays by policy","Querying the .onion address through normal DNS, which returns the vendor's physical location directly now","Asking the marketplace administrator, who is legally obligated to disclose all vendor identities on request","Analyzing metadata, language patterns, and operational leaks in listings, messages, and reused accounts"], correct:3, explanation:"Metadata and OPSEC leaks aid attribution; marketplaces do not publish addresses, .onion has no DNS location, and admins are not obligated to disclose." },
  { id:71053, domain:6, level:2, question:"What does 'timestomping' accomplish for malware?", options:["It falsifies a file's timestamps to blend the malicious file in with legitimate files and mislead timelines","It synchronizes the system clock accurately with an authoritative internet time server once every hour in this scenario as well.","It permanently freezes the system clock so that no new events can ever be recorded in any log again ever","It stamps a legal notice onto each file indicating the exact time the investigation formally began today"], correct:0, explanation:"Timestomping falsifies timestamps to evade timeline analysis; it is not clock sync, freezing time, or legal stamping." },
  { id:71054, domain:6, level:1, question:"Which is a defining trait of a computer virus specifically?", options:["It spreads entirely on its own across networks without needing any host file or any user interaction","It attaches to a host file or program and requires that host to be executed in order to spread further","It exists only in volatile memory and leaves absolutely no trace on the storage device whatsoever at all","It is a legitimate optimization tool that safely cleans temporary files from the computer each week"], correct:1, explanation:"A virus needs a host and user execution; self-spreading describes a worm, memory-only is fileless, and cleanup tools are benign." },
  { id:71055, domain:6, level:3, question:"An analyst extracts an RC4 key and encrypted config from a sample. What is the most useful next step for the investigation?", options:["Publish the RC4 key on the marketplace so other analysts can purchase access to the config for a fee","Delete the key immediately to ensure the malware can never decrypt its own configuration data again","Decrypt the config with the key to reveal C2 servers and campaign parameters for blocking and hunting","Email the encrypted config to the attacker and politely request that they provide the plaintext version"], correct:2, explanation:"Decrypting the config exposes actionable IOCs; selling the key, deleting it, or asking the attacker are all counterproductive." },
  { id:71056, domain:6, level:2, question:"Why is behavioral analysis sometimes more revealing than static analysis for heavily obfuscated malware?", options:["Static analysis is always faster and more complete, so behavioral analysis is never actually necessary at all","Behavioral analysis physically removes the obfuscation from the file on disk before it is ever executed","Obfuscated malware cannot run at all, so only static analysis of the dormant file is ever truly possible","Obfuscation hides code from static tools, but running the sample forces its true actions into the open"], correct:3, explanation:"Running obfuscated malware exposes behavior static tools miss; static is not always complete, behavior does not de-obfuscate the file, and the malware does run." },
  { id:71057, domain:6, level:2, question:"What is the purpose of a YARA rule's 'meta' section?", options:["It holds descriptive information like author, date, and reference notes that document the rule for humans","It contains the executable machine code that the rule injects into any file it successfully matches in this scenario as well.","It stores the private key used to decrypt any malware that the rule identifies during a scan operation","It defines the network ports on which the rule will actively listen for incoming malicious connections"], correct:0, explanation:"The meta section stores human-readable documentation; it does not contain executable code, decryption keys, or port definitions." },
  { id:71058, domain:6, level:1, question:"What best describes a 'backdoor' installed by malware?", options:["A front-facing login page that the organization intentionally publishes for all of its remote employees","A covert method of bypassing normal authentication to regain access to a compromised system later","A physical rear door of the data center building that requires a badge for authorized staff to enter","A scheduled maintenance script that installs approved security updates on servers overnight automatically"], correct:1, explanation:"A backdoor covertly bypasses authentication; it is not a public login page, a physical door, or a maintenance script." },
  { id:71059, domain:6, level:3, question:"A sample loads a legitimate signed executable and then side-loads a malicious DLL alongside it. What is this technique called?", options:["Certificate stapling, which attaches a fresh revocation status to a TLS certificate during a handshake","Disk mirroring, which writes identical data to two drives simultaneously for redundancy and fault tolerance","DLL side-loading, where a trusted signed binary is abused to load and execute an attacker-supplied DLL","Port forwarding, which redirects inbound network traffic from one port to another on a gateway device"], correct:2, explanation:"Abusing a signed binary to load a malicious DLL is side-loading; stapling, mirroring, and port forwarding are unrelated concepts." },
  { id:71060, domain:6, level:2, question:"Which of the following is a legitimate concern when analyzing malware that connects to a live C2 server?", options:["Contacting the C2 automatically and permanently arrests the attacker, which may violate their legal rights","Contacting the C2 always downloads a free antivirus tool that cleans the analysis machine completely","Contacting the C2 physically damages the analyst's network card, requiring hardware replacement each time","Contacting the live C2 may alert the attacker or trigger additional payloads, so isolation is important"], correct:3, explanation:"Live C2 contact can tip off the attacker or pull more payloads, so isolate; it does not arrest anyone, deliver antivirus, or damage hardware." },
  { id:71061, domain:6, level:2, question:"What is the value of MITRE ATT&CK technique IDs (like T1059) in an incident report?", options:["They give a standardized shorthand so different teams describe the same adversary behavior consistently","They are secret codes that automatically unlock premium features in commercial security products now","They represent the exact dollar amount of damage each technique caused during the specific incident in this scenario as well.","They are cryptographic hashes that uniquely identify the individual attacker who used each technique"], correct:0, explanation:"ATT&CK IDs standardize behavior descriptions; they are not product unlock codes, damage figures, or attacker identifiers." },
  { id:71062, domain:6, level:1, question:"Which practice reduces the risk of a malware sample escaping the analysis environment?", options:["Analyzing the sample directly on the corporate domain controller so results reflect the real environment","Running the sample in an isolated virtual machine with no bridge to the production network or internet","Sharing the running sample across a network drive so multiple analysts can execute it at the same time","Disabling all logging on the analysis host so the malware cannot detect that it is being monitored closely"], correct:1, explanation:"An isolated VM limits escape; running on a domain controller, sharing over the network, or disabling logging all increase risk." },
  { id:71063, domain:6, level:3, question:"A sample only runs its payload when a specific registry value set by an earlier stage is present. What does this design achieve?", options:["It ensures the payload runs on every computer worldwide simultaneously regardless of prior infection state","It makes the payload run only on machines that have never been infected by any malware at any point ever","It enforces staged execution so the payload only runs on hosts already prepared by the initial infection","It guarantees the payload will decrypt correctly inside any analyst sandbox without additional preparation"], correct:2, explanation:"The registry check ties execution to a prepared host, thwarting isolated analysis; it is not about global execution, clean machines, or sandbox friendliness." },
  { id:71064, domain:6, level:2, question:"Why is it useful to identify the programming language or compiler used to build a malware sample?", options:["It legally identifies the specific human developer, whose name is always embedded by every compiler used","It automatically generates a working decryptor for any files the malware has encrypted on the victim host","It guarantees that the malware can be recompiled into a benign program simply by changing the language in this scenario as well.","It narrows down likely tooling and artifacts, aiding attribution and guiding the reverse-engineering approach"], correct:3, explanation:"Compiler identification aids attribution and analysis strategy; it does not name the developer, generate decryptors, or neutralize malware." },
  { id:71065, domain:6, level:2, question:"What is a realistic challenge in tracing cryptocurrency across multiple blockchains ('chain hopping')?", options:["Funds moved through cross-chain swaps break the single-ledger trail, requiring correlation across networks","Cross-chain swaps are impossible, so all cryptocurrency is confined to one blockchain for its entire life","Chain hopping automatically publishes the sender's legal name on each blockchain the funds pass through in this scenario as well.","Every blockchain shares one universal ledger, so chain hopping has no effect on traceability whatsoever"], correct:0, explanation:"Chain hopping fragments the trail across ledgers, complicating tracing; swaps are possible, do not reveal names, and ledgers are not universal." },
  { id:71066, domain:6, level:1, question:"What does 'IOC enrichment' typically involve?", options:["Physically increasing the file size of each indicator so it is easier to see in a spreadsheet report","Adding context to raw indicators, such as geolocation, reputation, and related campaigns, to aid decisions","Deleting all indicators that are older than one day so the threat feed only contains fresh entries","Encrypting the indicators so that only the analyst who created them can ever read the list again in this scenario as well."], correct:1, explanation:"Enrichment adds useful context to indicators; it is not padding file size, aggressive deletion, or encryption." },
  { id:71067, domain:6, level:3, question:"A sample performs a series of meaningless arithmetic loops before doing anything malicious. What technique is this meant to defeat?", options:["Static string extraction, which the arithmetic loops physically erase from the binary before it is scanned","Cryptographic hashing, which the loops prevent by continuously changing the file's contents on disk always","Sandbox time limits, since stalling code can outlast a sandbox's short monitoring window before acting","Network packet capture, which the arithmetic loops disable by shutting down the host's network adapter now"], correct:2, explanation:"Stalling code aims to outlast sandbox timeouts; it does not erase strings, alter the file's hash, or disable networking." },
  { id:71068, domain:6, level:2, question:"Which of the following best characterizes a 'wiper' malware?", options:["Malware that silently records keystrokes and periodically transmits them to a remote collection server","Malware that displays advertisements in the browser to generate revenue for its distributor over time","Malware that encrypts files reversibly and reliably restores them once a ransom payment is confirmed","Malware whose primary goal is to destroy or corrupt data rather than to steal it or extort a ransom"], correct:3, explanation:"A wiper destroys data; keystroke recording is a keylogger, ad display is adware, and reversible encryption is ransomware." },
  { id:71069, domain:6, level:2, question:"Why is a network-isolated 'gold image' snapshot valuable in a malware lab?", options:["It provides a clean, known baseline to revert to and to diff against after each sample is detonated","It automatically emails the analyst's manager a summary of every malware sample that has been run","It permanently prevents any malware from ever executing on that host by locking the file system fully","It converts every sample run on it into a signed, trusted application approved by the operating system"], correct:0, explanation:"A gold image gives a clean baseline for reverting and diffing; it does not email managers, block all execution, or sign samples." },
  { id:71070, domain:6, level:1, question:"What is the main function of a 'loader' in a malware chain?", options:["To physically load paper into a network printer so that phishing documents can be printed on demand","To retrieve, decrypt, and execute the next stage of malware in memory on the compromised system","To back up the victim's files to a secure location before the main malicious payload is ever executed","To display a friendly progress bar reassuring the user that a legitimate installation is proceeding well"], correct:1, explanation:"A loader fetches and runs the next stage; it is not a printer feeder, a backup tool, or a benign progress indicator." },
  { id:71071, domain:6, level:3, question:"A malware uses a scheduled task, a Run key, AND a service all pointing to itself. Why use multiple persistence methods?", options:["The operating system requires exactly three persistence methods before any program is allowed to autostart","Multiple methods physically make the malware run three times faster than a single persistence entry would","Redundancy ensures the malware survives if one persistence mechanism is discovered and removed by defenders","Each method decrypts a different third of the payload, so all three are mandatory for the malware to run in this scenario as well."], correct:2, explanation:"Multiple mechanisms add resilience against removal; the OS imposes no three-method rule, and they do not affect speed or split the payload." },
  { id:71072, domain:6, level:2, question:"What is the purpose of correlating a malware sample's behavior against known threat actor TTPs?", options:["It automatically issues an international arrest warrant for the threat actor the moment a match is found","It converts the malware sample into a harmless decoy that can be safely distributed to end users now","It guarantees the threat actor will immediately cease all operations against the victim organization","It supports attribution and helps anticipate the actor's likely follow-on actions during an intrusion"], correct:3, explanation:"TTP correlation aids attribution and anticipation; it does not issue warrants, neutralize samples, or stop actors." },
  { id:71073, domain:6, level:2, question:"Why do mobile banking trojans on Android request accessibility service permissions?", options:["Accessibility permissions let the malware read screen content and simulate taps to hijack banking sessions","Accessibility permissions are required by law for any app that a bank publishes to its own customers now","Accessibility permissions physically increase the phone's screen brightness for visually impaired users only","Accessibility permissions automatically encrypt the phone's storage to protect it from all future malware"], correct:0, explanation:"Accessibility abuse enables screen reading and tap simulation for fraud; it is not a legal requirement, a brightness feature, or storage encryption." },
  { id:71074, domain:6, level:1, question:"What is 'sandbox detonation' most commonly used to produce?", options:["A physical explosion that destroys the analysis hardware to prevent the malware from ever spreading in this scenario as well.","A behavioral report detailing the sample's file, registry, network, and process activity during execution","A signed certificate proving the sample is safe for distribution to the organization's end users now","A refund of the ransom payment automatically credited back to the victim's bank account within a day"], correct:1, explanation:"Detonation yields a behavioral activity report; it is not a physical explosion, a safety certificate, or a ransom refund." },
  { id:71075, domain:6, level:3, question:"A sample queries process information specifically for a debug port. What is the sample most likely doing?", options:["Querying the process for its network debug port so it can open a legitimate remote support session now","Requesting additional memory from the operating system before it begins parsing a large input file in this scenario as well.","Checking whether a debugger is attached, an anti-debugging technique to detect and evade dynamic analysis","Verifying the process is digitally signed by a trusted vendor before allowing it to continue executing"], correct:2, explanation:"Debug-port queries detect an attached debugger for anti-analysis; it is not a network port query, a memory request, or a signature check." },
  { id:71076, domain:6, level:2, question:"Why is threat intelligence sharing (e.g., via ISACs) valuable after analyzing malware?", options:["Sharing legally transfers all liability for the incident to whichever organization receives the IOCs first","Sharing automatically patches the underlying vulnerability across every organization in the sharing group","Sharing guarantees the attacker will be arrested within twenty-four hours of the IOCs being distributed","Sharing IOCs and TTPs lets peer organizations detect and defend against the same threat more quickly"], correct:3, explanation:"Sharing improves collective detection and defense; it does not transfer liability, auto-patch systems, or guarantee arrests." },
  { id:71077, domain:6, level:2, question:"What is a common indicator that a system is part of a botnet?", options:["Regular beaconing to an external server on a fixed interval, often with little corresponding user activity","The computer displaying the correct time in the taskbar after a routine network time synchronization now","The user successfully printing a document to the office network printer during normal business hours in this scenario as well.","The presence of a manufacturer-installed recovery partition that shipped with the computer originally"], correct:0, explanation:"Periodic beaconing with no user activity signals botnet membership; a correct clock, normal printing, and a recovery partition are benign." },
  { id:71078, domain:6, level:1, question:"What does 'C2 beaconing' refer to?", options:["A lighthouse-style visual signal that malware displays on the monitor to alert the attacker of success","The periodic check-in traffic an infected host sends to its command-and-control server for instructions","The routine broadcast a wireless router sends to advertise its network name to nearby client devices in this scenario as well.","The heartbeat a hard drive emits to confirm it is functioning normally to the storage controller chip"], correct:1, explanation:"Beaconing is periodic C2 check-in traffic; it is not a visual signal, a Wi-Fi broadcast, or a drive heartbeat." },
  { id:71079, domain:6, level:3, question:"A sample enumerates running processes and terminates any named after common analysis tools. What is the goal of this behavior?", options:["To free system memory for the user by closing background applications they no longer actively need now","To comply with a corporate policy that permits only one application to run on the host at any given time","To disable analysis and monitoring tools so the malware can operate without being observed or captured","To improve battery life on a laptop by shutting down processes that consume excessive power while idle"], correct:2, explanation:"Killing analysis tools is anti-analysis evasion; it is not helpful memory management, policy compliance, or battery saving." },
  { id:71080, domain:6, level:2, question:"Why might an analyst use a debugger to single-step through a packed malware sample?", options:["To physically repair the corrupted sectors of the hard drive where the malware originally resided at first","To automatically translate the sample's assembly instructions into the analyst's native spoken language","To permanently encrypt the sample so that it can never be executed again on any other host machine ever","To reach the point where the sample finishes unpacking itself in memory and then dump the real code"], correct:3, explanation:"Single-stepping reaches the unpacked state for dumping; it does not repair disks, translate speech, or encrypt the sample." },
  { id:71081, domain:6, level:2, question:"Which of the following would a YARA rule be LEAST able to do on its own?", options:["Attribute a sample to a specific named human attacker with legal certainty based solely on byte patterns","Match a distinctive sequence of bytes that appears in a particular malware family's unpacking stub code","Flag a file that contains a specific combination of suspicious strings above a defined match threshold","Identify a known packer by matching signature bytes commonly found at the entry point of the binary in this scenario as well."], correct:0, explanation:"YARA matches patterns but cannot legally attribute samples to a named human; byte matching, string thresholds, and packer detection are all within its scope." },
  { id:71082, domain:6, level:1, question:"What is the purpose of a malware 'family' classification?", options:["To physically sort infected computers by the family names of the employees who normally use them","To group related samples that share code or behavior so defenders can reason about them collectively","To assign each malware sample a legal surname for use in official court filing documentation only","To determine which family member in a household is responsible for a home computer becoming infected"], correct:1, explanation:"Family classification groups related samples for collective defense; it is not sorting by employee names, legal surnames, or household blame." },
  { id:71083, domain:6, level:3, question:"A sample stores C2 addresses inside image files using steganography. Why do attackers use this technique?", options:["It compresses the C2 addresses to a single bit each, allowing thousands of servers in one tiny image file","It legally protects the C2 addresses as copyrighted artwork that investigators are forbidden to examine","It hides the C2 data inside seemingly innocent images, helping the configuration evade content inspection","It automatically rotates the C2 addresses every second so the image must be re-downloaded continuously"], correct:2, explanation:"Steganography conceals C2 data in images to evade inspection; it is not extreme compression, legal protection, or automatic rotation." },
  { id:71084, domain:6, level:2, question:"What is the main investigative benefit of reconstructing a malware's execution timeline?", options:["It automatically undoes every action the malware performed, returning the system to its original state","It legally proves the attacker's guilt beyond doubt without any need for corroborating technical evidence","It physically prevents the malware from executing again by rewriting the affected files on the disk now","It clarifies the sequence of actions, helping determine scope, initial access, and what data was affected"], correct:3, explanation:"A timeline clarifies scope and sequence; it does not auto-remediate, prove guilt alone, or prevent re-execution." },
  { id:71085, domain:6, level:2, question:"Which statement about the relationship between IOCs and behavioral detection is most accurate?", options:["IOCs catch known threats precisely, while behavioral detection can catch novel variants IOCs would miss","IOCs and behavioral detection are identical, so using one makes the other completely redundant always","Behavioral detection can only ever detect threats that already have a published hash-based indicator","IOCs automatically evolve on their own to detect brand-new malware without any analyst involvement at all"], correct:0, explanation:"IOCs and behavioral detection complement each other; they are not identical, behavior is not hash-dependent, and IOCs do not self-evolve." },
  { id:71086, domain:6, level:1, question:"What is a 'command-and-control channel' most fundamentally?", options:["The physical cable connecting a keyboard to a computer so that typed commands reach the processor","The communication path an attacker uses to direct infected machines and receive stolen data from them","The internal bus that carries control signals between the CPU and the graphics card on the motherboard","The remote control device used to change channels on a television from across the living room couch"], correct:1, explanation:"A C2 channel carries attacker commands and stolen data; it is not a keyboard cable, an internal bus, or a TV remote." },
  { id:71087, domain:6, level:3, question:"A sample uses certificate pinning for its C2 TLS connection. Why would malware authors do this?", options:["To make the malware run faster by skipping the normal certificate validation steps during the handshake","To legally register the malware's traffic as protected communication that investigators cannot inspect in this scenario as well.","To prevent security tools from intercepting the C2 traffic with a substituted man-in-the-middle certificate","To automatically share the C2 server's private key with any analyst who inspects the network traffic now"], correct:2, explanation:"Pinning defeats TLS interception by inspection tools; it is not a speed optimization, a legal protection, or key sharing." },
  { id:71088, domain:6, level:2, question:"What is a practical reason to preserve the original malware sample alongside the analysis report?", options:["It automatically translates the analysis report into every language spoken within the organization now","It permanently prevents the malware from being analyzed by any competing security vendor in the future","It legally obligates the malware author to provide technical support to the analysis team on request in this scenario as well.","It allows re-analysis, verification of findings, and future comparison as new intelligence becomes available"], correct:3, explanation:"Preserving the sample enables re-analysis and verification; it does not translate reports, block competitors, or obligate authors." },
  { id:71089, domain:6, level:2, question:"Which of the following best describes 'defense evasion' as a malware tactic category?", options:["Techniques the malware uses to avoid detection, such as obfuscation, disabling tools, and hiding artifacts","The legal defense strategy an attacker's lawyer uses to argue against charges in a criminal court case","The physical security guards stationed at the entrance to a data center to prevent unauthorized entry in this scenario as well.","The insurance policy an organization buys to cover financial losses resulting from a cyber attack event"], correct:0, explanation:"Defense evasion covers techniques to dodge detection; it is not a courtroom strategy, physical guards, or an insurance policy." },
  { id:71090, domain:6, level:3, question:"An analyst finds malware embedding a decoy document that opens while the payload installs silently. What is the decoy's purpose?", options:["To physically shred any paper documents on the victim's desk before the malware begins its main routine now in this scenario as well.","To reassure the victim that the file is benign, reducing suspicion while the real payload runs in the background","To automatically report the infection to the antivirus vendor so the sample can be added to signatures fast","To encrypt the decoy so that only the malware author can ever read the harmless content shown to the victim"], correct:1, explanation:"A decoy document lowers victim suspicion while the payload runs; it does not shred paper, report to vendors, or need encryption." },
  { id:71091, domain:6, level:2, question:"Why is analyzing a malware's imported functions (imports) useful even before running it?", options:["The imports list the victim's stored passwords in plaintext, letting the analyst recover the account instantly","The imports contain the attacker's home mailing address so investigators can serve legal papers directly to them","The imported APIs hint at capabilities like networking, encryption, or process injection the malware may use","The imports guarantee the exact runtime behavior with no need to ever execute the sample dynamically at all"], correct:2, explanation:"Imports hint at capability; they do not store victim passwords, hold attacker addresses, or fully guarantee runtime behavior." },
  { id:71092, domain:6, level:1, question:"What is a keylogger designed to capture?", options:["The temperature of the computer's processor so that overheating conditions can be logged for the user in this scenario as well.","The exact battery charge level of a laptop over time so its remaining runtime can be estimated closely","The physical dimensions of the keyboard so that a correctly sized protective cover can be ordered later","The keystrokes a user types, which can expose passwords, messages, and other sensitive typed information"], correct:3, explanation:"A keylogger captures typed keystrokes; it does not log CPU temperature, battery level, or keyboard dimensions." },
  { id:71093, domain:6, level:3, question:"A sample deletes itself from disk after copying to a new location and establishing persistence. Why do this?", options:["To remove the original dropped file from its known download path, hindering discovery and forensic recovery","To free enough disk space that the victim's operating system can install a large pending feature update now","To comply with a licensing term that requires the installer to remove itself after completing installation","To physically defragment the disk so the newly created persistent copy loads faster on the next system boot"], correct:0, explanation:"Self-deletion of the original hinders discovery and recovery; it is not about disk space, licensing, or defragmentation." },
  { id:71094, domain:6, level:2, question:"What is the investigative purpose of extracting strings from a memory dump rather than only from a disk file?", options:["Memory strings are always shorter than disk strings, so they are simply faster and cheaper to review","Memory strings can reveal decrypted payloads, C2 addresses, and injected code that never appear on disk","Memory strings physically overwrite the disk file, ensuring the malware can never be executed again ever","Memory strings automatically translate any obfuscated code into clean readable source for the analyst"], correct:1, explanation:"Runtime memory holds decrypted data absent from disk; it is not about being shorter, overwriting disk, or auto-translating code." },
  { id:71095, domain:6, level:1, question:"What is a 'sinkhole' in the context of botnet and C2 investigation?", options:["A physical drainage pit in a data center floor used to dispose of decommissioned old hard drives safely","A software bug that causes a program to crash whenever it attempts to open a specially crafted input file","Redirecting malicious domain traffic to a controlled server so infected hosts can be observed and studied","A backup vault where an organization stores encrypted copies of its most sensitive corporate documents"], correct:2, explanation:"A sinkhole redirects malicious traffic to a controlled server for study; it is not a drainage pit, a crash bug, or a backup vault." },
  { id:71096, domain:6, level:3, question:"An analyst finds a ransomware sample that also exfiltrates files before encrypting them. What tactic does this reflect?", options:["A benign backup routine, since copying files before encryption simply preserves them for the victim to keep","A hardware diagnostic that reads every file once to verify the storage device has no failing disk sectors","A licensing audit that inventories installed software to confirm the organization holds valid product keys","Double extortion, where attackers threaten to leak stolen data in addition to demanding a decryption ransom"], correct:3, explanation:"Copying data out before encryption is double extortion; it is not a benign backup, a hardware diagnostic, or a licensing audit." },
  { id:71097, domain:6, level:2, question:"Why do analysts often examine a sample's PDB path or debug string if one is left in the binary?", options:["It may reveal folder names, usernames, or project names that offer clues about the author and build system","It contains the complete decryption key for any ransomware the sample deploys against a victim's files","It lists the exact retail price the attacker charged customers for the malware on an underground forum","It guarantees the physical street address of the developer, which every compiler embeds automatically in this scenario as well."], correct:0, explanation:"PDB paths can leak author and build clues; they are not decryption keys, price lists, or guaranteed addresses." },
  { id:71098, domain:6, level:1, question:"What does the term 'dark web' generally refer to?", options:["The portion of any website that appears with a dark color theme enabled in the visitor's browser settings","Web content on overlay networks like Tor that requires specific software and is not indexed by search engines","A private company intranet that employees reach with normal browsers using their corporate login accounts","Any website that happens to be temporarily offline because its hosting server is undergoing maintenance in this scenario as well."], correct:1, explanation:"The dark web is overlay-network content needing special software; it is not a color theme, a corporate intranet, or an offline site." },
  { id:71099, domain:6, level:3, question:"A sample hooks the SSDT (System Service Descriptor Table) to intercept system calls. What is this most indicative of?", options:["A routine user preference sync that keeps desktop settings consistent across the person's multiple computers in this scenario as well.","A standard printer driver installation that registers the device so documents can be sent to it for printing","A kernel-mode rootkit intercepting system calls to hide files, processes, or registry keys from detection tools","A harmless disk indexing service that catalogs file names so desktop search returns results more quickly now"], correct:2, explanation:"SSDT hooking to intercept system calls is a kernel rootkit trait; it is not preference sync, a printer driver, or disk indexing." },
  { id:71100, domain:6, level:2, question:"Why is it risky to rely only on a single antivirus engine's verdict when triaging a suspected malware sample?", options:["A single engine is legally binding, so its verdict cannot be questioned or reviewed by any other analyst at all","A single engine physically deletes the sample after scanning, leaving nothing for a second engine to examine","A single engine always encrypts its own results so that no competing vendor can ever read or verify them","One engine may miss what others catch, so a single clean or malicious verdict can be incomplete or misleading"], correct:3, explanation:"Engines vary in coverage, so one verdict may mislead; verdicts are not legally binding, do not delete samples, or encrypt results." },
];
